const GRAMMAR_DATA=[{id:1,level:"n3",pattern:"〜てしまう",meaning:"（完成）做完了；（遗憾）不小心做了",desc:"表示动作的完了，有时带有遗憾或后悔的语气。",appear:12,ex_jp:"財布を忘れてしまった。",ex_read:"さいふを わすれて しまった。",ex_cn:"把钱包忘了（很遗憾）。"},{id:2,level:"n3",pattern:"〜ている",meaning:"（持续状态）正在做；（结果状态）处于……状态",desc:"表示动作正在进行，或动作结果仍然持续。",appear:12,ex_jp:"今、本を読んでいます。",ex_read:"いま、ほんを よんでいます。",ex_cn:"现在正在看书。"},{id:3,level:"n3",pattern:"〜ために",meaning:"为了〜（目的）；因为〜（原因）",desc:"前接动词辞书形表目的；前接名词・普通形表原因。",appear:11,ex_jp:"日本語を上手になるために、毎日練習します。",ex_read:"にほんごを じょうずに なるために、まいにち れんしゅうします。",ex_cn:"为了日语变好，每天练习。"},{id:4,level:"n3",pattern:"〜ようになる",meaning:"变得能〜；逐渐〜起来",desc:"表示状态或能力的变化，多表示渐进性变化。",appear:11,ex_jp:"毎日練習したら、泳げるようになった。",ex_read:"まいにち れんしゅうしたら、およげるように なった。",ex_cn:"每天练习后，变得能游泳了。"},{id:5,level:"n3",pattern:"〜たり〜たりする",meaning:"（举例）做做这个、做做那个",desc:"列举几个动作，表示交替进行或不限定地举例。",appear:11,ex_jp:"週末は映画を見たり、友達と話したりします。",ex_read:"しゅうまつは えいがを みたり、ともだちと はなしたりします。",ex_cn:"周末或看电影、或和朋友聊天。"},{id:6,level:"n3",pattern:"〜なければならない",meaning:"必须〜；不得不〜",desc:"表示义务或必要，语气较强。",appear:10,ex_jp:"明日までにレポートを出さなければならない。",ex_read:"あしたまでに れぽーとを ださなければ ならない。",ex_cn:"必须在明天之前提交报告。"},{id:7,level:"n3",pattern:"〜と思う",meaning:"我觉得〜；我认为〜",desc:"表示主观判断、想法或推测。",appear:10,ex_jp:"彼は来ないと思います。",ex_read:"かれは こないと おもいます。",ex_cn:"我觉得他不会来。"},{id:8,level:"n3",pattern:"〜てもいい",meaning:"〜也可以；可以〜",desc:"表示许可，允许某种行为。",appear:10,ex_jp:"ここで写真を撮ってもいいですか。",ex_read:"ここで しゃしんを とっても いいですか。",ex_cn:"这里可以拍照吗？"},{id:9,level:"n3",pattern:"〜てはいけない",meaning:"不可以〜；禁止〜",desc:"表示禁止，不允许某种行为。",appear:10,ex_jp:"ここでタバコを吸ってはいけません。",ex_read:"ここで たばこを すっては いけません。",ex_cn:"这里不可以抽烟。"},{id:10,level:"n3",pattern:"〜かもしれない",meaning:"也许〜；说不定〜",desc:"表示不确定的推测，可能性约为50%。",appear:10,ex_jp:"明日は雨が降るかもしれない。",ex_read:"あしたは あめが ふるかも しれない。",ex_cn:"明天也许会下雨。"},{id:11,level:"n3",pattern:"〜でしょう",meaning:"大概〜吧；应该〜吧",desc:"表示推测，带有一定根据，语气较肯定。",appear:9,ex_jp:"彼は忙しいでしょう。",ex_read:"かれは いそがしいでしょう。",ex_cn:"他大概很忙吧。"},{id:12,level:"n3",pattern:"〜によって",meaning:"根据〜；因〜而异；通过〜（手段）",desc:"表示根据、依据、原因或手段，用法多样。",appear:9,ex_jp:"国によって文化が違います。",ex_read:"くにに よって ぶんかが ちがいます。",ex_cn:"文化因国家而异。"},{id:13,level:"n3",pattern:"〜ことができる",meaning:"能〜；会〜；可以〜",desc:"表示能力或可能性，可由〜（ら）れる代替。",appear:9,ex_jp:"彼女は五か国語を話すことができます。",ex_read:"かのじょは ごかこくごを はなす ことが できます。",ex_cn:"她能说五种语言。"},{id:14,level:"n3",pattern:"〜ことにする",meaning:"决定〜（主动决定）",desc:"表示说话人自己做出的决定。",appear:9,ex_jp:"来年、日本に留学することにした。",ex_read:"らいねん、にほんに りゅうがくする ことに した。",ex_cn:"决定明年去日本留学。"},{id:15,level:"n3",pattern:"〜ことになる",meaning:"（结果）变成〜；（客观上）定了〜",desc:"表示自然、客观的结果，或别人・组织做出的决定。",appear:9,ex_jp:"来月から大阪で働くことになった。",ex_read:"らいげつから おおさかで はたらく ことに なった。",ex_cn:"（结果）从下个月起要在大阪工作了。"},{id:16,level:"n3",pattern:"〜ば〜ほど",meaning:"越〜越〜",desc:"表示程度随条件增加而增加。",appear:8,ex_jp:"練習すればするほど、上手になる。",ex_read:"れんしゅうすれば するほど、じょうずに なる。",ex_cn:"越练习越厉害。"},{id:17,level:"n3",pattern:"〜てあげる",meaning:"（我）为别人做〜",desc:"表示给予者为受益者做某事（施益方向：向外）。",appear:8,ex_jp:"友達に日本語を教えてあげた。",ex_read:"ともだちに にほんごを おしえて あげた。",ex_cn:"（我）教朋友日语了。"},{id:18,level:"n3",pattern:"〜てもらう",meaning:"（我）请（别人）做〜；让别人做〜",desc:"表示受益者（我/我方）从施益者处获得动作。",appear:8,ex_jp:"先生に説明してもらいました。",ex_read:"せんせいに せつめいして もらいました。",ex_cn:"请老师给我解释了。"},{id:19,level:"n3",pattern:"〜てくれる",meaning:"（别人）为我做〜",desc:"表示他人为说话人做某事，含感谢语气。",appear:8,ex_jp:"母が弁当を作ってくれた。",ex_read:"ははが べんとうを つくって くれた。",ex_cn:"妈妈给我做了便当。"},{id:20,level:"n3",pattern:"〜らしい",meaning:"好像〜；听说〜（根据传闻）",desc:"根据外部信息做出推测，信息来源于见闻或外表。",appear:8,ex_jp:"彼女は医者らしい。",ex_read:"かのじょは いしゃ らしい。",ex_cn:"她好像是医生。"},{id:21,level:"n3",pattern:"〜ようだ",meaning:"好像〜；似乎〜（根据直接感知）",desc:"根据说话人直接观察或感知做出判断。",appear:8,ex_jp:"外は寒いようです。",ex_read:"そとは さむい ようです。",ex_cn:"外面好像很冷。"},{id:22,level:"n3",pattern:"〜そうだ（様態）",meaning:"看起来〜；马上要〜（样态）",desc:"根据视觉观察推测即将发生或当前状态，前接ます形。",appear:8,ex_jp:"雨が降りそうです。",ex_read:"あめが ふりそうです。",ex_cn:"看起来要下雨了。"},{id:23,level:"n3",pattern:"〜そうだ（伝聞）",meaning:"据说〜；听说〜（传闻）",desc:"传达从他处得到的信息，前接普通形。",appear:7,ex_jp:"明日は試験があるそうです。",ex_read:"あしたは しけんが あるそうです。",ex_cn:"听说明天有考试。"},{id:24,level:"n3",pattern:"〜てから",meaning:"做了〜之后，再〜",desc:"明确先做前项，再做后项。",appear:8,ex_jp:"手を洗ってから食べてください。",ex_read:"てを あらって から たべてください。",ex_cn:"洗完手再吃。"},{id:25,level:"n3",pattern:"〜前に",meaning:"〜之前",desc:"表示时间顺序，在前项动作发生之前做后项。",appear:8,ex_jp:"寝る前に歯を磨きます。",ex_read:"ねる まえに はを みがきます。",ex_cn:"睡觉前刷牙。"},{id:26,level:"n3",pattern:"〜後で",meaning:"〜之后",desc:"表示时间顺序，在前项结束后做后项。",appear:7,ex_jp:"宿題をした後で、テレビを見ます。",ex_read:"しゅくだいを した あとで、てれびを みます。",ex_cn:"做完作业后看电视。"},{id:27,level:"n3",pattern:"〜ながら",meaning:"一边〜一边〜",desc:"两个动作同时进行，主动作在后。",appear:8,ex_jp:"音楽を聴きながら勉強します。",ex_read:"おんがくを きき ながら べんきょうします。",ex_cn:"一边听音乐一边学习。"},{id:28,level:"n3",pattern:"〜と（条件）",meaning:"一〜就〜（自然条件）",desc:"前项为条件，后项自然而然地发生，多用于自然规律或说明。",appear:9,ex_jp:"春になると、桜が咲きます。",ex_read:"はるに なると、さくらが さきます。",ex_cn:"一到春天，樱花就开了。"},{id:29,level:"n3",pattern:"〜たら",meaning:"如果〜的话（假设）；〜了之后",desc:"表示假设条件或时间先后，用法最广泛的条件句。",appear:9,ex_jp:"時間があったら、映画を見に行きましょう。",ex_read:"じかんが あったら、えいがを みに いきましょう。",ex_cn:"如果有时间的话，去看电影吧。"},{id:30,level:"n3",pattern:"〜ば",meaning:"如果〜的话（条件）",desc:"表示假设条件，后项通常是希望、期待等表达，多用于正面条件。",appear:8,ex_jp:"お金があれば、旅行に行きたい。",ex_read:"おかねが あれば、りょこうに いきたい。",ex_cn:"如果有钱的话，想去旅行。"},{id:31,level:"n3",pattern:"〜なら",meaning:"如果是〜的话（话题限定）",desc:"以对方说的话或共同话题为前提进行判断、建议。",appear:8,ex_jp:"東京に行くなら、新幹線が便利ですよ。",ex_read:"とうきょうに いくなら、しんかんせんが べんりですよ。",ex_cn:"如果要去东京，新干线很方便哦。"},{id:32,level:"n3",pattern:"〜んです（のです）",meaning:"（说明·解释）是因为〜；是〜呀",desc:"用于解释原因、强调说明或引出话题。",appear:9,ex_jp:"どうして遅れたんですか。",ex_read:"どうして おくれた んですか。",ex_cn:"为什么迟到了呀？"},{id:33,level:"n3",pattern:"〜てほしい",meaning:"希望（对方）做〜",desc:"表示说话人希望他人做某事，对象用に标记。",appear:7,ex_jp:"もっと静かにしてほしい。",ex_read:"もっと しずかに して ほしい。",ex_cn:"希望（你）再安静一点。"},{id:34,level:"n3",pattern:"〜たほうがいい",meaning:"最好〜（建议）",desc:"表示建议，劝说对方去做或不去做某事。",appear:8,ex_jp:"熱があるから、病院へ行ったほうがいい。",ex_read:"ねつが あるから、びょういんへ いった ほうが いい。",ex_cn:"有发烧，最好去医院。"},{id:35,level:"n3",pattern:"〜ために（目的）",meaning:"为了〜",desc:"表示目的，前接动词辞书形或名词の。",appear:9,ex_jp:"健康のために運動します。",ex_read:"けんこうの ために うんどうします。",ex_cn:"为了健康而运动。"},{id:36,level:"n3",pattern:"〜だけ",meaning:"只〜；仅〜",desc:"表示限定，只有这个范围，别无其他。",appear:7,ex_jp:"水だけ飲んだ。",ex_read:"みずだけ のんだ。",ex_cn:"只喝了水。"},{id:37,level:"n3",pattern:"〜ばかり",meaning:"净〜；老是〜",desc:"表示偏向于某一方，有时带批评语气。",appear:7,ex_jp:"ゲームばかりしている。",ex_read:"げーむばかり している。",ex_cn:"老是在打游戏。"},{id:38,level:"n3",pattern:"〜だろう",meaning:"大概〜吧（推测）",desc:"说话人的推测，だ的推量形，口语常用。",appear:7,ex_jp:"彼は今頃寝ているだろう。",ex_read:"かれは いまごろ ねているだろう。",ex_cn:"他这会儿大概在睡觉吧。"},{id:39,level:"n3",pattern:"〜のに",meaning:"（转折）明明〜却；（遗憾）要是〜就好了",desc:"表示转折期待，前项与后项相悖，含惊讶或不满。",appear:7,ex_jp:"一生懸命勉強したのに、試験に落ちた。",ex_read:"いっしょうけんめい べんきょうしたのに、しけんに おちた。",ex_cn:"明明拼命学习了，却没通过考试。"},{id:40,level:"n3",pattern:"〜けど（が）",meaning:"（转折）虽然〜但是",desc:"表示转折，口语常用けど，正式用が。",appear:8,ex_jp:"行きたいけど、時間がない。",ex_read:"いきたいけど、じかんが ない。",ex_cn:"虽然想去，但没时间。"},{id:41,level:"n3",pattern:"〜し、〜し",meaning:"（并列原因）既〜又〜",desc:"列举多个原因或理由，语气较柔和。",appear:7,ex_jp:"安いし、おいしいし、よく行くレストランです。",ex_read:"やすいし、おいしいし、よく いく れすとらんです。",ex_cn:"既便宜又好吃，是我常去的餐厅。"},{id:42,level:"n3",pattern:"〜まま",meaning:"保持〜状态不变",desc:"前项状态保持不变，进行后项动作。",appear:6,ex_jp:"靴を履いたまま家に入った。",ex_read:"くつを はいたまま いえに はいった。",ex_cn:"穿着鞋就进了家。"},{id:43,level:"n3",pattern:"〜はずだ",meaning:"理应〜；应该〜（有根据的推测）",desc:"基于逻辑或知识做出有根据的推断。",appear:7,ex_jp:"彼女は今日来るはずだ。",ex_read:"かのじょは きょう くる はずだ。",ex_cn:"她今天应该会来的（按理来说）。"},{id:44,level:"n3",pattern:"〜とき",meaning:"〜的时候",desc:"表示某一时间点或时间段。",appear:9,ex_jp:"子供のとき、よく川で泳いだ。",ex_read:"こどもの とき、よく かわで およんだ。",ex_cn:"小时候经常在河里游泳。"},{id:45,level:"n3",pattern:"〜ために（原因）",meaning:"因为〜；由于〜",desc:"表示原因，多用于客观、消极结果。",appear:7,ex_jp:"病気のために会社を休んだ。",ex_read:"びょうきの ために かいしゃを やすんだ。",ex_cn:"因为生病，请了公司的假。"},{id:46,level:"n2",pattern:"〜にもかかわらず",meaning:"尽管〜；虽然〜却",desc:"表示转折，前后情况不一致，书面语较多。",appear:10,ex_jp:"雨にもかかわらず、試合は行われた。",ex_read:"あめに もかかわらず、しあいは おこなわれた。",ex_cn:"尽管下雨，比赛还是举行了。"},{id:47,level:"n2",pattern:"〜に対して",meaning:"对于〜；针对〜",desc:"表示对象、对比或态度。",appear:10,ex_jp:"先生の質問に対して、学生が答えた。",ex_read:"せんせいの しつもんに たいして、がくせいが こたえた。",ex_cn:"学生回答了老师的问题。"},{id:48,level:"n2",pattern:"〜において",meaning:"在〜（方面/场合）",desc:"书面语，表示场所、领域、时间等。",appear:9,ex_jp:"スポーツにおいて、チームワークが重要だ。",ex_read:"すぽーつに おいて、ちーむわーくが じゅうようだ。",ex_cn:"在体育方面，团队合作很重要。"},{id:49,level:"n2",pattern:"〜に関して",meaning:"关于〜；有关〜",desc:"表示话题范围，书面语较多，同〜について但更正式。",appear:9,ex_jp:"環境問題に関して、意見を述べた。",ex_read:"かんきょう もんだいに かんして、いけんを のべた。",ex_cn:"就环境问题发表了意见。"},{id:50,level:"n2",pattern:"〜によると",meaning:"据〜说；根据〜",desc:"引用信息来源，表示根据。",appear:9,ex_jp:"天気予報によると、明日は晴れるそうだ。",ex_read:"てんきよほうに よると、あしたは はれるそうだ。",ex_cn:"根据天气预报，明天会晴。"},{id:51,level:"n2",pattern:"〜ことから",meaning:"由于〜；从〜可以看出",desc:"以前项事实为依据，引出后项的判断或结论。",appear:8,ex_jp:"顔が赤いことから、恥ずかしいとわかる。",ex_read:"かおが あかいことから、はずかしいと わかる。",ex_cn:"从脸红这一点可以看出他很害羞。"},{id:52,level:"n2",pattern:"〜ことなく",meaning:"不〜地；没有〜就",desc:"表示没有做前项动作，就进行了后项，书面语。",appear:7,ex_jp:"休むことなく、働き続けた。",ex_read:"やすむ ことなく、はたらきつづけた。",ex_cn:"不休息地持续工作了。"},{id:53,level:"n2",pattern:"〜だけでなく",meaning:"不仅〜，而且〜",desc:"表示追加，前项已经如此，后项也同样。",appear:9,ex_jp:"彼は英語だけでなく、中国語も話せる。",ex_read:"かれは えいごだけでなく、ちゅうごくごも はなせる。",ex_cn:"他不仅会说英语，还会说中文。"},{id:54,level:"n2",pattern:"〜わけではない",meaning:"并非〜；不是说〜",desc:"部分否定，表示并不是字面意思那样。",appear:8,ex_jp:"嫌いなわけではないが、得意ではない。",ex_read:"きらいな わけではないが、とくいでは ない。",ex_cn:"并非不喜欢，只是不擅长。"},{id:55,level:"n2",pattern:"〜わけにはいかない",meaning:"不能〜；没办法〜（情理上不允许）",desc:"表示根据情理、道义，主观上无法接受或无法实行。",appear:8,ex_jp:"約束があるから、行かないわけにはいかない。",ex_read:"やくそくが あるから、いかない わけには いかない。",ex_cn:"因为有约，没办法不去。"},{id:56,level:"n2",pattern:"〜一方だ",meaning:"越来越〜；持续〜",desc:"表示某种状态或倾向单方面持续增强，无法逆转。",appear:7,ex_jp:"物価が上がる一方だ。",ex_read:"ぶっかが あがる いっぽうだ。",ex_cn:"物价越来越高。"},{id:57,level:"n2",pattern:"〜一方で",meaning:"一方面〜，另一方面〜",desc:"表示对比，同一主体在两个方面的表现。",appear:7,ex_jp:"彼女は仕事をしている一方で、子育てもしている。",ex_read:"かのじょは しごとを している いっぽうで、こそだても している。",ex_cn:"她一方面工作，另一方面也在养育孩子。"},{id:58,level:"n2",pattern:"〜せいで",meaning:"都是因为〜（负面原因）",desc:"表示原因，暗含责怪或负面结果，同〜せいか、〜せいにする。",appear:8,ex_jp:"雨のせいで、試合が中止になった。",ex_read:"あめの せいで、しあいが ちゅうしに なった。",ex_cn:"都是因为下雨，比赛取消了。"},{id:59,level:"n2",pattern:"〜おかげで",meaning:"多亏〜（正面原因）",desc:"表示原因，含感谢或正面结果。",appear:8,ex_jp:"先生のおかげで、試験に合格した。",ex_read:"せんせいの おかげで、しけんに ごうかくした。",ex_cn:"多亏老师，通过了考试。"},{id:60,level:"n2",pattern:"〜に違いない",meaning:"一定是〜；肯定〜",desc:"说话人确信度较高的推断。",appear:8,ex_jp:"あの車は高いに違いない。",ex_read:"あの くるまは たかいに ちがいない。",ex_cn:"那辆车一定很贵。"},{id:61,level:"n2",pattern:"〜にしたがって",meaning:"随着〜；按照〜",desc:"表示随某变化而变化，或按规则行动。",appear:7,ex_jp:"経済の発展にしたがって、生活が豊かになった。",ex_read:"けいざいの はってんに したがって、せいかつが ゆたかに なった。",ex_cn:"随着经济发展，生活变得富裕了。"},{id:62,level:"n2",pattern:"〜に伴って",meaning:"随着〜；伴随〜",desc:"表示伴随变化，前后同步变化，比〜にしたがって更强调同步。",appear:7,ex_jp:"高齢化に伴って、医療費が増加している。",ex_read:"こうれいかに ともなって、いりょうひが ぞうかしている。",ex_cn:"随着老龄化，医疗费用不断增加。"},{id:63,level:"n2",pattern:"〜ものの",meaning:"虽然〜但是（转折）",desc:"前项事实成立，但后项结果出乎意料，书面语。",appear:7,ex_jp:"試験に合格したものの、自信が持てない。",ex_read:"しけんに ごうかくした ものの、じしんが もてない。",ex_cn:"虽然考试合格了，但还是没有自信。"},{id:64,level:"n2",pattern:"〜ことにしている",meaning:"（习惯上）坚持〜",desc:"表示说话人已经决定并习惯化的行为。",appear:7,ex_jp:"毎朝30分走ることにしている。",ex_read:"まいあさ さんじゅっぷん はしることに している。",ex_cn:"坚持每天早上跑30分钟。"},{id:65,level:"n2",pattern:"〜ようとする",meaning:"试图〜；想要〜（努力尝试）",desc:"表示主体积极尝试去做某事，强调意图和努力。",appear:7,ex_jp:"ドアを開けようとしたが、開かなかった。",ex_read:"どあを あけようとしたが、あかなかった。",ex_cn:"试图开门，但没开成。"},{id:66,level:"n2",pattern:"〜ではないか",meaning:"不是〜吗（反问确认）",desc:"用反问语气确认或强调某种看法，口语常用じゃないか。",appear:6,ex_jp:"こんなにきれいじゃないか。",ex_read:"こんなに きれいじゃ ないか。",ex_cn:"这难道不是很漂亮吗？"},{id:67,level:"n2",pattern:"〜にすぎない",meaning:"只不过是〜；不过是〜",desc:"表示程度有限，轻视或降低某事重要性。",appear:6,ex_jp:"それは単なる噂にすぎない。",ex_read:"それは たんなる うわさに すぎない。",ex_cn:"那只不过是谣言。"},{id:68,level:"n2",pattern:"〜を通じて（通して）",meaning:"通过〜；经由〜",desc:"表示手段、媒介或时间持续。",appear:7,ex_jp:"ボランティアを通じて多くを学んだ。",ex_read:"ぼらんてぃあを つうじて おおくを まなんだ。",ex_cn:"通过志愿活动学到了很多。"},{id:69,level:"n2",pattern:"〜に加えて",meaning:"除〜之外还〜；加上〜",desc:"在前项基础上再追加后项，表示累加。",appear:6,ex_jp:"能力に加えて、努力も必要だ。",ex_read:"のうりょくに くわえて、どりょくも ひつようだ。",ex_cn:"除了能力之外，还需要努力。"},{id:70,level:"n2",pattern:"〜わけだ",meaning:"难怪〜；所以〜（理所当然）",desc:'表示从前项事实得出理所当然的结论，带有"恍然大悟"的语感。',appear:7,ex_jp:"彼は5年日本に住んでいたわけだから、日本語が上手だ。",ex_read:"かれは ごねん にほんに すんでいた わけだから、にほんごが じょうずだ。",ex_cn:"他在日本住了5年，日语当然好了。"},{id:71,level:"n2",pattern:"〜かねない",meaning:"说不定会〜（负面可能性）",desc:"表示有可能发生不好的结果，带有警示语气。",appear:7,ex_jp:"無理をすると体を壊しかねない。",ex_read:"むりを すると からだを こわしかねない。",ex_cn:"勉强的话，说不定会搞坏身体。"},{id:72,level:"n2",pattern:"〜かねる",meaning:"难以〜；不能〜（无法接受）",desc:"表示在情感上或立场上很难做某事，委婉拒绝。",appear:6,ex_jp:"その条件には承諾しかねます。",ex_read:"その じょうけんには しょうだく しかねます。",ex_cn:"对于那个条件，难以同意。"},{id:73,level:"n2",pattern:"〜てたまらない",meaning:"〜得不得了；极其〜",desc:"表示某种感情或感觉强烈到无法忍受，自发性情感。",appear:7,ex_jp:"試験が心配でたまらない。",ex_read:"しけんが しんぱいで たまらない。",ex_cn:"对考试担心得不得了。"},{id:74,level:"n2",pattern:"〜てならない",meaning:"非常〜；不由得〜",desc:"感情、感觉自然而然地涌现，无法控制，稍显文言。",appear:6,ex_jp:"故郷が懐かしくてならない。",ex_read:"こきょうが なつかしくて ならない。",ex_cn:"非常想念故乡。"},{id:75,level:"n2",pattern:"〜上で",meaning:"在〜方面；做〜之后",desc:"前接名词の或动词辞书形，表示前提条件或做完某事后。",appear:7,ex_jp:"健康の上で大切なことを話した。",ex_read:"けんこうの うえで たいせつな ことを はなした。",ex_cn:"谈到了在健康方面重要的事情。"},{id:76,level:"n2",pattern:"〜上に",meaning:"不仅〜，而且〜（程度追加）",desc:"表示前项已然，后项在此基础上进一步，累加信息。",appear:7,ex_jp:"彼女は美人の上に、頭もいい。",ex_read:"かのじょは びじんの うえに、あたまも いい。",ex_cn:"她不仅漂亮，而且还很聪明。"},{id:77,level:"n2",pattern:"〜ほど",meaning:"越〜越〜；〜得…程度",desc:"表示程度，越做前项后项程度越深；也表示比较基准。",appear:8,ex_jp:"彼ほど優秀な学生はいない。",ex_read:"かれほど ゆうしゅうな がくせいは いない。",ex_cn:"没有比他更优秀的学生了。"},{id:78,level:"n2",pattern:"〜さえ〜ば",meaning:"只要〜就行了",desc:"前接最低限度的条件，表示只要满足前项就足够了。",appear:7,ex_jp:"お金さえあれば、何でもできる。",ex_read:"おかねさえ あれば、なんでも できる。",ex_cn:"只要有钱，什么都能做。"},{id:80,level:"n2",pattern:"〜とともに",meaning:"和〜一起；随着〜",desc:"表示共同或伴随变化，同〜と一緒に但更书面。",appear:7,ex_jp:"時間の経過とともに、悲しみが薄れた。",ex_read:"じかんの けいかとともに、かなしみが うすれた。",ex_cn:"随着时间流逝，悲伤淡化了。"},{id:81,level:"n2",pattern:"〜に関わらず",meaning:"不管〜；无论〜",desc:"表示不受前项条件影响，都执行后项，书面语。",appear:7,ex_jp:"年齢に関わらず、参加できます。",ex_read:"ねんれいに かかわらず、さんかできます。",ex_cn:"无论年龄，均可参加。"},{id:82,level:"n2",pattern:"〜にわたって",meaning:"长达〜（时间/范围延续）",desc:"表示时间或空间范围的持续延伸。",appear:6,ex_jp:"3時間にわたって会議が続いた。",ex_read:"さんじかんに わたって かいぎが つづいた。",ex_cn:"会议持续了3个小时之久。"},{id:83,level:"n2",pattern:"〜に比べて",meaning:"与〜相比",desc:"表示比较基准，口语也常用。",appear:8,ex_jp:"去年に比べて、今年は暑い。",ex_read:"きょねんに くらべて、ことしは あつい。",ex_cn:"与去年相比，今年更热。"},{id:84,level:"n2",pattern:"〜をはじめ（として）",meaning:"以〜为首；〜等",desc:"列举代表性的人或事物，同时包含其他。",appear:7,ex_jp:"東京をはじめ、大阪、名古屋も有名だ。",ex_read:"とうきょうを はじめ、おおさか、なごやも ゆうめいだ。",ex_cn:"以东京为首，大阪、名古屋也很有名。"},{id:85,level:"n2",pattern:"〜から見ると",meaning:"从〜来看；从〜角度看",desc:"表示判断的视角或立场。",appear:6,ex_jp:"外国人から見ると、日本の習慣は独特だ。",ex_read:"がいこくじんから みると、にほんの しゅうかんは どくとくだ。",ex_cn:"从外国人角度来看，日本的习惯很独特。"},{id:86,level:"n2",pattern:"〜として",meaning:"作为〜；以〜身份",desc:"表示立场、资格、地位或身份。",appear:8,ex_jp:"教師として、学生に責任がある。",ex_read:"きょうしとして、がくせいに せきにんが ある。",ex_cn:"作为教师，对学生有责任。"},{id:87,level:"n2",pattern:"〜に対し",meaning:"对于〜；针对〜（书面简洁形）",desc:"〜に対して的书面简洁形，用法相同。",appear:8,ex_jp:"批判に対し、説明した。",ex_read:"ひはんに たいし、せつめいした。",ex_cn:"针对批评进行了说明。"},{id:88,level:"n2",pattern:"〜ものだ",meaning:"本来〜；（感慨）真是〜啊",desc:"表示一般规律、常识，或感慨，情感色彩强。",appear:7,ex_jp:"時間が経つのは早いものだ。",ex_read:"じかんが たつのは はやいものだ。",ex_cn:"时光流逝真是快啊。"},{id:89,level:"n2",pattern:"〜ものだから",meaning:"因为〜（辩解·解释原因）",desc:"表示原因，带有辩解或解释语气，偏口语。",appear:6,ex_jp:"急いでいたものだから、忘れてしまった。",ex_read:"いそいでいた ものだから、わすれて しまった。",ex_cn:"因为赶时间，所以忘了。"},{id:90,level:"n2",pattern:"〜に応じて",meaning:"根据〜；按照〜",desc:"根据情况或要求做出相应回应或调整。",appear:7,ex_jp:"要求に応じて、計画を変えた。",ex_read:"ようきゅうに おうじて、けいかくを かえた。",ex_cn:"根据要求，改变了计划。"},{id:91,level:"n2",pattern:"〜を通して",meaning:"通过〜（整个过程/媒介）",desc:"表示经由某手段、媒介，或在某段时间内持续。",appear:6,ex_jp:"旅行を通して、多くの文化を学んだ。",ex_read:"りょこうを とおして、おおくの ぶんかを まなんだ。",ex_cn:"通过旅行学到了很多文化。"},{id:92,level:"n2",pattern:"〜にほかならない",meaning:"无非是〜；正是〜",desc:"强调前项是唯一正确的解释，书面语。",appear:6,ex_jp:"成功は努力の結果にほかならない。",ex_read:"せいこうは どりょくの けっかに ほかならない。",ex_cn:"成功无非是努力的结果。"},{id:93,level:"n2",pattern:"〜というのは",meaning:"所谓〜是指；〜这件事",desc:"引出话题或定义的解释，说明前项内容。",appear:7,ex_jp:"「一期一会」というのは、一生に一度の出会いという意味だ。",ex_read:"いちごいちえ というのは、いっしょうに いちどの であいという いみだ。",ex_cn:'所谓"一期一会"，是指一生中仅有一次的相遇。'},{id:94,level:"n2",pattern:"〜からといって",meaning:"不能因为〜就〜（驳斥以偏概全）",desc:"即使前项成立，也不能用来理由化后项，表示批驳。",appear:6,ex_jp:"英語が話せるからといって、仕事ができるとは限らない。",ex_read:"えいごが はなせるからと いって、しごとができるとは かぎらない。",ex_cn:"不能因为会说英语就说工作能力强。"},{id:95,level:"n2",pattern:"〜にしても",meaning:"即使〜也；就算〜也",desc:"表示即使前项成立，后项也是如此，让步假设。",appear:6,ex_jp:"失敗したにしても、諦めてはいけない。",ex_read:"しっぱいした にしても、あきらめては いけない。",ex_cn:"就算失败了，也不能放弃。"},{id:96,level:"n2",pattern:"〜にあたって",meaning:"在〜之际；值〜之时",desc:"表示某个重要时间节点，在此时机做某事，书面语。",appear:7,ex_jp:"卒業にあたって、先生に感謝した。",ex_read:"そつぎょうに あたって、せんせいに かんしゃした。",ex_cn:"值毕业之际，向老师表示了感谢。"},{id:97,level:"n2",pattern:"〜に際して",meaning:"在〜之际（正式场合）",desc:"比〜にあたって更正式，多用于仪式或重要场合。",appear:6,ex_jp:"入社に際して、研修を受けた。",ex_read:"にゅうしゃに さいして、けんしゅうを うけた。",ex_cn:"入职之际，接受了培训。"},{id:98,level:"n2",pattern:"〜を契機に",meaning:"以〜为契机",desc:"表示某件事成为转折点或出发点，书面语。",appear:6,ex_jp:"留学を契機に、人生が変わった。",ex_read:"りゅうがくを けいきに、じんせいが かわった。",ex_cn:"以留学为契机，人生改变了。"},{id:99,level:"n2",pattern:"〜かといえば",meaning:"说起〜的话；要说是否〜",desc:"引出话题，后接说话人的判断或解说。",appear:5,ex_jp:"好きかといえば、好きではない。",ex_read:"すきか といえば、すきでは ない。",ex_cn:"说喜不喜欢的话，并不喜欢。"},{id:100,level:"n2",pattern:"〜ずに（は）いられない",meaning:"不得不〜；忍不住〜",desc:"表示内心冲动无法克制，某种感情或行为自发涌出。",appear:6,ex_jp:"あの映画を見て、泣かずにはいられなかった。",ex_read:"あの えいがを みて、なかずに は いられなかった。",ex_cn:"看了那部电影，忍不住哭了。"},{id:101,level:"n2",pattern:"〜というより",meaning:"与其说〜不如说",desc:"对前项表达进行修正，提出更准确的说法。",appear:6,ex_jp:"怒っているというより、悲しんでいる。",ex_read:"おこっている というより、かなしんでいる。",ex_cn:"与其说是生气，不如说是悲伤。"},{id:102,level:"n2",pattern:"〜に反して",meaning:"与〜相反；违背〜",desc:"表示结果、行为与预期、规定等相悖。",appear:6,ex_jp:"予想に反して、試験が難しかった。",ex_read:"よそうに はんして、しけんが むずかしかった。",ex_cn:"与预期相反，考试很难。"},{id:104,level:"n2",pattern:"〜に基づいて",meaning:"基于〜；根据〜",desc:"表示以某事实、规则、数据为基础，做出判断或行动。",appear:7,ex_jp:"データに基づいて、分析した。",ex_read:"でーたに もとづいて、ぶんせきした。",ex_cn:"基于数据进行了分析。"},{id:105,level:"n2",pattern:"〜に沿って",meaning:"沿着〜；按照〜",desc:"按照某方向、路线、规则行动。",appear:6,ex_jp:"計画に沿って、工事を進めた。",ex_read:"けいかくに そって、こうじを すすめた。",ex_cn:"按照计划推进了工程。"},{id:106,level:"n2",pattern:"〜あげく（に・の）",meaning:"结果（不好）〜",desc:"表示前项的长时间努力或复杂过程后，得出不好的结果。",appear:6,ex_jp:"いろいろ考えたあげく、会社を辞めることにした。",ex_read:"いろいろ かんがえた あげく、かいしゃを やめる ことにした。",ex_cn:"左思右想之后，决定辞职。"},{id:107,level:"n2",pattern:"〜あまり（に）",meaning:"太〜以至于；过度〜导致",desc:"表示程度过甚，因而产生了某种结果。",appear:6,ex_jp:"忙しさのあまり、食事を忘れてしまった。",ex_read:"いそがしさの あまり、しょくじを わすれてしまった。",ex_cn:"太忙了以至于忘了吃饭。"},{id:108,level:"n2",pattern:"〜以上（は）",meaning:"既然〜",desc:"表示确定的事实为前提，后接说话人的决心、判断或义务。",appear:7,ex_jp:"学生である以上、勉強を最優先すべきだ。",ex_read:"がくせいで あるいじょう、べんきょうを さいゆうせん すべきだ。",ex_cn:"既然是学生，就应该以学习为最优先。"},{id:109,level:"n2",pattern:"〜一方（で）",meaning:"一方面〜另一方面；与〜相反",desc:"表示对比或并列的两个方面。",appear:7,ex_jp:"収入が増える一方で、支出も増えている。",ex_read:"しゅうにゅうが ふえる いっぽうで、ししゅつも ふえている。",ex_cn:"一方面收入增加，另一方面支出也在增加。"},{id:111,level:"n2",pattern:"〜限り（は）",meaning:"只要〜就",desc:"表示在前项条件持续期间，后项状态或行为一直持续。",appear:7,ex_jp:"私がいる限り、あなたを守ります。",ex_read:"わたしが いるかぎり、あなたを まもります。",ex_cn:"只要我在，就会保护你。"},{id:112,level:"n2",pattern:"〜がたい",meaning:"难以〜",desc:"表示从客观上看很难做到某事，多用于书面语。",appear:6,ex_jp:"彼の気持ちは理解しがたい。",ex_read:"かれの きもちは りかいしがたい。",ex_cn:"难以理解他的心情。"},{id:113,level:"n2",pattern:"〜からして",meaning:"单从〜来看",desc:"举出代表性例子来推断整体情况，含有最低限度之意。",appear:5,ex_jp:"彼の態度からして、誠実ではない。",ex_read:"かれの たいどからして、せいじつでは ない。",ex_cn:"单从他的态度来看，就不诚实。"},{id:114,level:"n2",pattern:"〜からには",meaning:"既然〜",desc:"确定事实为前提，后接强烈的决心、义务或劝告。",appear:6,ex_jp:"約束したからには、必ず守ります。",ex_read:"やくそくした からには、かならず まもります。",ex_cn:"既然约好了，就一定会遵守。"},{id:115,level:"n2",pattern:"〜きる・きれない",meaning:"完全〜；能完全〜；不能完全〜",desc:"表示彻底完成或无法完全完成某种行为。",appear:6,ex_jp:"こんなにたくさん食べきれない。",ex_read:"こんなに たくさん たべきれない。",ex_cn:"这么多吃不完。"},{id:116,level:"n2",pattern:"〜げ",meaning:"看似〜；好像〜的样子",desc:"接在形容词或动词连用形后，表示从外表看出的某种样子或感觉。",appear:5,ex_jp:"彼は嬉しげに笑った。",ex_read:"かれは うれしげに わらった。",ex_cn:"他看似高兴地笑了。"},{id:117,level:"n2",pattern:"〜こそ",meaning:"正是〜才",desc:'强调主语或原因，表示"不是别的，正是这个"。',appear:7,ex_jp:"今度こそ、試験に合格したい。",ex_read:"こんどこそ、しけんに ごうかくしたい。",ex_cn:"这次一定要考试合格。"},{id:119,level:"n2",pattern:"〜ことだ",meaning:"应该〜（忠告）",desc:"表示建议或忠告，语气较为直接。",appear:6,ex_jp:"健康のために、早寝早起きをすることだ。",ex_read:"けんこうの ために、はやねはやおきを することだ。",ex_cn:"为了健康，应该早睡早起。"},{id:121,level:"n2",pattern:"〜ざるを得ない",meaning:"不得不〜",desc:"表示没有其他选择，迫于形势而必须做某事。",appear:7,ex_jp:"事実を認めざるを得ない。",ex_read:"じじつを みとめざるを えない。",ex_cn:"不得不承认事实。"},{id:122,level:"n2",pattern:"〜次第",meaning:"一〜就；取决于",desc:"有两种用法：表示前项动作完成后立即做后项；或表示结果由前项决定。",appear:7,ex_jp:"資料が届き次第、すぐに連絡します。",ex_read:"しりょうが とどきしだい、すぐに れんらくします。",ex_cn:"资料一到就立刻联系您。"},{id:123,level:"n2",pattern:"〜たびに",meaning:"每当〜就",desc:"表示每次发生前项，后项都会出现。",appear:6,ex_jp:"この写真を見るたびに、学生時代を思い出す。",ex_read:"この しゃしんを みるたびに、がくせいじだいを おもいだす。",ex_cn:"每当看到这张照片，就会想起学生时代。"},{id:124,level:"n2",pattern:"〜ついでに",meaning:"顺便〜",desc:"利用做某事的机会，顺便做另一件事。",appear:5,ex_jp:"買い物に行くついでに、郵便局に寄った。",ex_read:"かいものに いくついでに、ゆうびんきょくに よった。",ex_cn:"去买东西顺便去了趟邮局。"},{id:125,level:"n2",pattern:"〜つつある",meaning:"正在〜",desc:"表示某动作或变化正在持续过程中，较正式的书面表达。",appear:6,ex_jp:"経済は回復しつつある。",ex_read:"けいざいは かいふくしつつある。",ex_cn:"经济正在复苏。"},{id:126,level:"n2",pattern:"〜といっても",meaning:"虽说〜",desc:"先承认前项，但对实际内容或程度加以修正。",appear:5,ex_jp:"プロといっても、まだ初心者に近い。",ex_read:"ぷろと いっても、まだ しょしんしゃに ちかい。",ex_cn:"虽说是专业的，但仍接近初学者水平。"},{id:128,level:"n2",pattern:"〜ないことはない",meaning:"也不是不〜",desc:"双重否定表示有所保留的肯定。",appear:4,ex_jp:"行きたくないことはないが、時間がない。",ex_read:"いきたくない ことは ないが、じかんが ない。",ex_cn:"也不是不想去，只是没有时间。"},{id:129,level:"n2",pattern:"〜に限って",meaning:"偏偏〜；唯独〜",desc:"表示特别限定，常有与一般情况不同的含义。",appear:5,ex_jp:"大事な時に限って、バスが遅れる。",ex_read:"だいじな ときに かぎって、ばすが おくれる。",ex_cn:"偏偏在重要的时候，公交会晚点。"},{id:130,level:"n2",pattern:"〜に限らず",meaning:"不仅〜；不限于〜",desc:"表示不限于前项，其他也包含在内。",appear:6,ex_jp:"男性に限らず、女性もこの仕事に挑戦している。",ex_read:"だんせいに かぎらず、じょせいも このしごとに ちょうせんしている。",ex_cn:"不仅男性，女性也在挑战这份工作。"},{id:132,level:"n2",pattern:"〜を問わず",meaning:"不论〜；无论〜",desc:"表示不受前项条件的限制，后项都成立。",appear:6,ex_jp:"経験を問わず、意欲のある人を募集する。",ex_read:"けいけんを とわず、いよくの あるひとを ぼしゅうする。",ex_cn:"不论经验，招募有干劲的人。"},{id:133,level:"n2",pattern:"〜をめぐって",meaning:"围绕〜",desc:"表示以某个话题或问题为中心展开讨论或争议。",appear:5,ex_jp:"新政策をめぐって、激しい議論が交わされた。",ex_read:"しんせいさくを めぐって、はげしい ぎろんが かわされた。",ex_cn:"围绕新政策展开了激烈的讨论。"},{id:134,level:"n2",pattern:"〜をもとに",meaning:"以〜为基础",desc:"表示以某事为材料、依据或参考。",appear:6,ex_jp:"実際の体験をもとに、小説を書いた。",ex_read:"じっさいの たいけんを もとに、しょうせつを かいた。",ex_cn:"以实际经历为基础写了小说。"},{id:135,level:"n2",pattern:"〜ばかりか",meaning:"不仅〜而且",desc:"表示递进，前项自不必说，后项也成立。",appear:6,ex_jp:"彼は英語ばかりか、中国語も話せる。",ex_read:"かれは えいご ばかりか、ちゅうごくごも はなせる。",ex_cn:"他不仅会英语，还会说中文。"},{id:136,level:"n3",pattern:"〜あげる",meaning:"给〜（对方）",desc:"我/我方给他人某物或做某事。",appear:9,ex_jp:"友達にプレゼントをあげた。",ex_read:"ともだちに ぷれぜんとを あげた。",ex_cn:"给了朋友礼物。"},{id:137,level:"n3",pattern:"〜あまり〜ない",meaning:"不太〜",desc:"与否定连用，表示程度不深或不常做。",appear:9,ex_jp:"私はあまり肉を食べない。",ex_read:"わたしは あまり にくを たべない。",ex_cn:"我不太吃肉。"},{id:138,level:"n3",pattern:"〜あまりにも",meaning:"过于〜",desc:"表示程度过分，超出正常范围。",appear:8,ex_jp:"あまりにも高くて買えない。",ex_read:"あまりにも たかくて かえない。",ex_cn:"太贵了买不起。"},{id:139,level:"n3",pattern:"〜合う",meaning:"互相〜",desc:"动词连用形＋合う，表示动作的相互性。",appear:8,ex_jp:"お互いに助け合うことが大切だ。",ex_read:"おたがいに たすけあうことが たいせつだ。",ex_cn:"互相帮助很重要。"},{id:140,level:"n3",pattern:"〜ばいい",meaning:"只要〜就好了",desc:"表示建议或条件满足即可。",appear:8,ex_jp:"わからないなら、先生に聞けばいい。",ex_read:"わからないなら、せんせいに きけばいい。",ex_cn:"不明白的话，问老师就好了。"},{id:141,level:"n3",pattern:"〜ばよかった",meaning:"要是…就好了（后悔）",desc:"表示对已发生事情的后悔或遗憾。",appear:7,ex_jp:"もっと勉強すればよかった。",ex_read:"もっと べんきょうすれば よかった。",ex_cn:"要是再努力学就好了。"},{id:142,level:"n3",pattern:"〜ば〜のに",meaning:"要是…的话就好了（非现实）",desc:"表示与事实相反的愿望或遗憾。",appear:7,ex_jp:"彼が来ればいいのに。",ex_read:"かれが くれば いいのに。",ex_cn:"他要是能来就好了。"},{id:143,level:"n3",pattern:"〜ばかりで",meaning:"光〜；只〜",desc:"表示单一状态，强调仅此而已，没有其他。",appear:7,ex_jp:"彼は文句ばかりで、自分では何もしない。",ex_read:"かれは もんく ばかりで、じぶんでは なにもしない。",ex_cn:"他光发牢骚，自己什么也不做。"},{id:144,level:"n3",pattern:"〜ばかりでなく",meaning:"不仅〜而且",desc:"表示递进，与だけでなく类似。",appear:7,ex_jp:"彼は英語ばかりでなく、フランス語も話せる。",ex_read:"かれは えいご ばかりでなく、ふらんすごも はなせる。",ex_cn:"他不仅会英语，还会说法语。"},{id:145,level:"n3",pattern:"〜べきだ",meaning:"应该〜",desc:"表示义务、劝告或理想的做法。",appear:8,ex_jp:"約束は守るべきだ。",ex_read:"やくそくは まもるべきだ。",ex_cn:"应该遵守约定。"},{id:146,level:"n3",pattern:"〜べきではない",meaning:"不应该〜",desc:"べきだ的否定形式，表示不应该做。",appear:7,ex_jp:"人の秘密を勝手に話すべきではない。",ex_read:"ひとの ひみつを かってに はなすべきではない。",ex_cn:"不应该随便说别人的秘密。"},{id:147,level:"n3",pattern:"〜別に〜ない",meaning:"并不特别〜",desc:"与否定呼应，表示并不特别、没什么大不了的。",appear:7,ex_jp:"別に用はありません。",ex_read:"べつに ようは ありません。",ex_cn:"没什么特别的事。"},{id:148,level:"n3",pattern:"〜ぶりに",meaning:"时隔〜再次",desc:"表示经过较长时间后再次做某事。",appear:6,ex_jp:"10年ぶりに故郷に帰った。",ex_read:"じゅうねんぶりに こきょうに かえった。",ex_cn:"时隔10年回到了故乡。"},{id:149,level:"n3",pattern:"〜中（ちゅう）",meaning:"正在〜中；〜之中",desc:"表示正在进行的状态或某范围内。",appear:9,ex_jp:"ただいま会議中です。",ex_read:"ただいま かいぎちゅうです。",ex_cn:"现在正在开会。"},{id:150,level:"n3",pattern:"〜だらけ",meaning:"满是〜",desc:"强调某处大量存在不好的东西。",appear:6,ex_jp:"部屋がほこりだらけだ。",ex_read:"へやが ほこりだらけだ。",ex_cn:"房间满是灰尘。"},{id:151,level:"n3",pattern:"〜どんなに〜ても",meaning:"无论多么〜也",desc:"表示即使程度极端，结果也不变。",appear:7,ex_jp:"どんなに頑張っても、間に合わない。",ex_read:"どんなに がんばっても、まにあわない。",ex_cn:"无论怎么努力都来不及了。"},{id:152,level:"n3",pattern:"〜どうしても",meaning:"无论如何也",desc:"表示无论如何努力也难以做到。",appear:6,ex_jp:"どうしても彼の名前が思い出せない。",ex_read:"どうしても かれの なまえが おもいだせない。",ex_cn:"怎么也想不起他的名字。"},{id:153,level:"n3",pattern:"〜ふりをする",meaning:"装作〜的样子",desc:"表示假装成某种样子或状态。",appear:6,ex_jp:"知らないふりをした。",ex_read:"しらない ふりを した。",ex_cn:"装作不知道。"},{id:154,level:"n3",pattern:"〜がち",meaning:"容易〜；倾向于〜",desc:"多用于负面倾向，常接动词连用形或名词。",appear:7,ex_jp:"最近、忘れがちだ。",ex_read:"さいきん、わすれがちだ。",ex_cn:"最近容易忘事。"},{id:155,level:"n3",pattern:"〜気味",meaning:"有点〜；稍微〜",desc:"表示轻微倾向或状态，多用于负面。",appear:6,ex_jp:"少し風邪気味だ。",ex_read:"すこし かぜぎみだ。",ex_cn:"有点感冒的迹象。"},{id:156,level:"n3",pattern:"〜ごとに",meaning:"每〜",desc:"表示每隔一定单位就发生一次。",appear:7,ex_jp:"1時間ごとに薬を飲む。",ex_read:"いちじかんごとに くすりを のむ。",ex_cn:"每隔一小时喝药。"},{id:157,level:"n3",pattern:"〜ほど〜ない",meaning:"没有比〜更〜",desc:"表示最高级的比较。",appear:7,ex_jp:"彼ほど親切な人はいない。",ex_read:"かれほど しんせつな ひとは いない。",ex_cn:"没有人比他更亲切了。"},{id:158,level:"n3",pattern:"〜一度に",meaning:"同时；一下子",desc:"表示多个动作或事情同时进行。",appear:5,ex_jp:"一度にたくさん覚えようとしないで。",ex_read:"いちどに たくさん おぼえようと しないで。",ex_cn:"别想一下子记住太多。"},{id:159,level:"n3",pattern:"〜いくら〜ても",meaning:"无论怎么〜也",desc:"表示反复尝试但结果不变。",appear:6,ex_jp:"いくら説明しても彼はわかってくれない。",ex_read:"いくら せつめいしても かれは わかってくれない。",ex_cn:"无论怎么解释，他都不明白。"},{id:160,level:"n3",pattern:"〜以来",meaning:"自从〜以来",desc:"表示从过去某时点一直持续到现在。",appear:6,ex_jp:"日本に来て以来、一度も国に帰っていない。",ex_read:"にほんに きて いらい、いちども くにに かえっていない。",ex_cn:"来自从日本后，一次也没回过国。"},{id:161,level:"n3",pattern:"〜いただく",meaning:"承蒙给〜（自谦）",desc:"もらう的自谦语，表示从上级/长辈处接受。",appear:8,ex_jp:"先生にご説明いただきました。",ex_read:"せんせいに ごせつめい いただきました。",ex_cn:"承蒙老师为我们做了说明。"},{id:162,level:"n3",pattern:"〜かける",meaning:"开始〜；刚〜",desc:"表示动作刚开始或做到一半。",appear:7,ex_jp:"彼女は何か言いかけてやめた。",ex_read:"かのじょは なにか いいかけて やめた。",ex_cn:"她刚说了点什么又咽了回去。"},{id:163,level:"n3",pattern:"〜かけだ",meaning:"做到一半；没做完",desc:"表示动作进行到中途尚未完成。",appear:6,ex_jp:"食べかけの弁当がある。",ex_read:"たべかけの べんとうが ある。",ex_cn:"有吃到一半的便当。"},{id:164,level:"n3",pattern:"〜代わりに",meaning:"代替〜；作为交换",desc:"表示替代做某事或作为交换条件。",appear:7,ex_jp:"母の代わりに買い物に行った。",ex_read:"ははの かわりに かいものに いった。",ex_cn:"代替妈妈去购物了。"},{id:165,level:"n3",pattern:"〜くせに",meaning:"明明〜却（贬义）",desc:"表示责怪或讽刺的语气，常用于指责。",appear:6,ex_jp:"知らないくせに知ったふりをしている。",ex_read:"しらない くせに しった ふりを している。",ex_cn:"明明不知道却装作知道。"},{id:166,level:"n3",pattern:"〜くらい/ぐらい",meaning:"大约；至少；简直",desc:"表示程度、概数或最低限度。",appear:9,ex_jp:"これくらいのことは自分でできる。",ex_read:"これくらいのことは じぶんで できる。",ex_cn:"这点事我自己能做。"},{id:167,level:"n3",pattern:"〜始める",meaning:"开始〜",desc:"接动词连用形，表示动作开始。",appear:8,ex_jp:"急に雨が降り始めた。",ex_read:"きゅうに あめが ふりはじめた。",ex_cn:"突然开始下雨了。"},{id:168,level:"n3",pattern:"〜出す",meaning:"突然〜起来；开始〜",desc:"接动词连用形，表示动作突然开始。",appear:7,ex_jp:"彼は泣き出した。",ex_read:"かれは なきだした。",ex_cn:"他哭了起来。"},{id:169,level:"n3",pattern:"〜続ける",meaning:"继续〜",desc:"接动词连用形，表示动作持续进行。",appear:7,ex_jp:"2時間歩き続けた。",ex_read:"にじかん あるきつづけた。",ex_cn:"连续走了两个小时。"},{id:170,level:"n3",pattern:"〜終わる",meaning:"做完〜",desc:"接动词连用形，表示动作结束。",appear:7,ex_jp:"宿題をやり終わった。",ex_read:"しゅくだいを やりおわった。",ex_cn:"做完了作业。"},{id:171,level:"n3",pattern:"〜直す",meaning:"重新〜",desc:"接动词连用形，表示再做一次。",appear:5,ex_jp:"もう一度書き直してください。",ex_read:"もういちど かきなおして ください。",ex_cn:"请重新写一遍。"},{id:172,level:"n3",pattern:"〜すぎる",meaning:"过于〜；太〜",desc:"接动词连用形或形容词词干，表示过度。",appear:8,ex_jp:"食べすぎてお腹が痛い。",ex_read:"たべすぎて おなかが いたい。",ex_cn:"吃太多了肚子疼。"},{id:173,level:"n3",pattern:"〜やすい",meaning:"容易〜；好〜",desc:"接动词连用形，表示易于做某事。",appear:8,ex_jp:"このペンは書きやすい。",ex_read:"この ぺんは かきやすい。",ex_cn:"这支笔好写。"},{id:174,level:"n3",pattern:"〜にくい",meaning:"难以〜；不好〜",desc:"接动词连用形，表示难以做某事。",appear:7,ex_jp:"この漢字は覚えにくい。",ex_read:"この かんじは おぼえにくい。",ex_cn:"这个汉字难记。"},{id:175,level:"n3",pattern:"〜方",meaning:"〜的方法；〜的做法",desc:"接动词连用形，表示方法或方式。",appear:9,ex_jp:"この料理の作り方を教えてください。",ex_read:"この りょうりの つくりかたを おしえてください。",ex_cn:"请教我这道菜的做法。"},{id:176,level:"n3",pattern:"〜つもり",meaning:"打算〜",desc:"表示做某事的意图或打算。",appear:8,ex_jp:"来年、日本へ留学するつもりだ。",ex_read:"らいねん、にほんへ りゅうがくする つもりだ。",ex_cn:"打算明年去日本留学。"},{id:177,level:"n3",pattern:"〜予定",meaning:"预计〜；安排",desc:"表示预先的计划或安排。",appear:7,ex_jp:"来週、出張する予定です。",ex_read:"らいしゅう、しゅっちょうする よていです。",ex_cn:"预计下周出差。"},{id:178,level:"n3",pattern:"〜ところ",meaning:"正要〜；刚〜",desc:"表示时间点：～ところだ正要、～たところだ刚做完。",appear:8,ex_jp:"これから出かけるところだ。",ex_read:"これから でかける ところだ。",ex_cn:"正要出门。"},{id:179,level:"n3",pattern:"〜ているところ",meaning:"正在〜（时间点）",desc:"强调动作正在进行中的那个时间点。",appear:7,ex_jp:"今、電話しているところです。",ex_read:"いま、でんわして いるところです。",ex_cn:"现在正在打电话。"},{id:180,level:"n3",pattern:"〜たばかり",meaning:"刚刚〜",desc:"表示动作刚结束不久，距离现在很近。",appear:7,ex_jp:"日本に着いたばかりです。",ex_read:"にほんに ついた ばかりです。",ex_cn:"刚到日本。"},{id:181,level:"n3",pattern:"〜たて",meaning:"刚〜好的",desc:"用于刚完成、新鲜的状态，多接动作性名词。",appear:5,ex_jp:"焼きたてのパンはおいしい。",ex_read:"やきたての ぱんは おいしい。",ex_cn:"刚出炉的面包很好吃。"},{id:182,level:"n3",pattern:"〜うちに",meaning:"趁〜的时候；在〜过程中",desc:"表示在某一状态持续期间做某事。",appear:8,ex_jp:"明るいうちに帰ろう。",ex_read:"あかるい うちに かえろう。",ex_cn:"趁天亮回去吧。"},{id:183,level:"n3",pattern:"〜間/間に",meaning:"在〜期间（内）",desc:"〜間表示整个时间段内持续；〜間に表示在期间内某点发生。",appear:7,ex_jp:"夏休みの間に日本へ行った。",ex_read:"なつやすみの あいだに にほんへ いった。",ex_cn:"暑假期间去了日本。"},{id:184,level:"n3",pattern:"〜までに",meaning:"到〜为止（截止）",desc:"表示截止时间点，在此之前做某事。",appear:7,ex_jp:"明日までにレポートを提出してください。",ex_read:"あしたまでに れぽーとを ていしゅつしてください。",ex_cn:"请在明天之前提交报告。"},{id:185,level:"n3",pattern:"〜ので",meaning:"因为〜（客观原因）",desc:"表示客观原因理由，比から更礼貌柔和。",appear:10,ex_jp:"風邪を引いたので、学校を休みました。",ex_read:"かぜを ひいたので、がっこうを やすみました。",ex_cn:"因为感冒了，所以请了假没去学校。"},{id:186,level:"n3",pattern:"〜と（発見）",meaning:"（发现）一〜就发现",desc:"表示做完前项动作后，发现了意外的结果。",appear:9,ex_jp:"ドアを開けると、猫がいた。",ex_read:"どあを あけると、ねこが いた。",ex_cn:"一开门，发现有一只猫。"},{id:187,level:"n3",pattern:"〜たら（発見）",meaning:"（发现）一〜后发现",desc:"做完前项后发现后项，为意外的结果。",appear:8,ex_jp:"部屋に行ったら、誰もいなかった。",ex_read:"へやに いったら、だれも いなかった。",ex_cn:"去了房间后发现一个人都没有。"},{id:188,level:"n3",pattern:"〜かと思うと",meaning:"刚一〜就〜",desc:"表示两个动作几乎同时发生，带有意外感。",appear:6,ex_jp:"彼は帰ってきたかと思うと、また出て行った。",ex_read:"かれは かえってきたかと おもうと、また でていった。",ex_cn:"他刚一回来，又出去了。"},{id:189,level:"n3",pattern:"〜たとたん",meaning:"刚一〜的瞬间",desc:"前项动作刚完成，后项立即发生。",appear:6,ex_jp:"立ち上がったとたん、めまいがした。",ex_read:"たちあがった とたん、めまいがした。",ex_cn:"刚一站起来就觉得头晕。"},{id:190,level:"n3",pattern:"〜た末/〜た結果",meaning:"经过〜之后；〜的结果",desc:"表示经过一番努力或过程后得出结果。",appear:6,ex_jp:"考えた末、彼と別れることにした。",ex_read:"かんがえた すえ、かれと わかれることにした。",ex_cn:"经过考虑后，决定和他分手。"},{id:191,level:"n3",pattern:"〜つつ",meaning:"一边〜一边；虽然〜但",desc:"表示同时进行两个动作，或逆接关系。",appear:7,ex_jp:"歩きつつ、本を読んでいる。",ex_read:"あるきつつ、ほんを よんでいる。",ex_cn:"一边走路一边看书。"},{id:192,level:"n3",pattern:"〜のみならず",meaning:"不仅〜而且",desc:"书面语，表示递进，比だけでなく更强。",appear:6,ex_jp:"彼は努力のみならず、才能もある。",ex_read:"かれは どりょく のみならず、さいのうも ある。",ex_cn:"他不仅努力，还有才华。"},{id:193,level:"n3",pattern:"〜はもとより",meaning:"不用说〜；当然〜",desc:"前项理所当然，后项更不用说或更进一步。",appear:6,ex_jp:"日本はもとより、アジア全体で人気がある。",ex_read:"にほんは もとより、あじあ ぜんたいで にんきが ある。",ex_cn:"在日本自不必说，在整个亚洲都很有人气。"},{id:194,level:"n3",pattern:"〜はもちろん",meaning:"〜自不必说",desc:"前项理所当然，后项进一步补充。",appear:7,ex_jp:"彼女は英語はもちろん、中国語もペラペラだ。",ex_read:"かのじょは えいごは もちろん、ちゅうごくごも ぺらぺらだ。",ex_cn:"她英语自不必说，中文也说得流利。"},{id:195,level:"n3",pattern:"〜とか",meaning:"〜什么的；听说是",desc:"表示举例或传闻。（用于列举非确定例子）",appear:6,ex_jp:"休みには旅行とか行きたい。",ex_read:"やすみには りょこうとか いきたい。",ex_cn:"放假想去旅行什么的。"},{id:196,level:"n3",pattern:"〜やら〜やら",meaning:"又〜又〜（列举）",desc:"列举几项，暗示还有其他。",appear:5,ex_jp:"泣くやら叫ぶやら大騒ぎだった。",ex_read:"なくやら さけぶやら おおさわぎだった。",ex_cn:"又哭又叫，闹翻了天。"},{id:197,level:"n3",pattern:"〜ところが",meaning:"然而；可是",desc:"表示逆接，后项多为与预期相反的事情。",appear:6,ex_jp:"買おうと思った。ところが、お金が足りなかった。",ex_read:"かおうと おもった。ところが、おかねが たりなかった。",ex_cn:"本想买。然而钱不够。"},{id:198,level:"n3",pattern:"〜としても",meaning:"就算〜也",desc:"表示假设让步，即使前项成立后项也不变。",appear:7,ex_jp:"行けるとしても、時間が短い。",ex_read:"いけるとしても、じかんが みじかい。",ex_cn:"就算能去，时间也很短。"},{id:199,level:"n3",pattern:"〜たところで",meaning:"即使〜也（没用）",desc:"表示即使做了前项，也达不到预期效果。",appear:6,ex_jp:"今さら謝ったところで、遅い。",ex_read:"いまさら あやまった ところで、おそい。",ex_cn:"事到如今即使道歉也晚了。"},{id:200,level:"n3",pattern:"〜から言って",meaning:"从〜来看",desc:"表示从某立场或角度做出判断。",appear:6,ex_jp:"私から言って、彼は信頼できる。",ex_read:"わたしから いって、かれは しんらいできる。",ex_cn:"从我的角度看，他值得信赖。"},{id:201,level:"n3",pattern:"〜からすると",meaning:"从〜来看（判断依据）",desc:"表示以某事物为基准进行判断。",appear:6,ex_jp:"あの態度からすると、彼は知らないようだ。",ex_read:"あの たいどからすると、かれは しらないようだ。",ex_cn:"从那个态度来看，他好像不知道。"},{id:202,level:"n3",pattern:"〜から見て",meaning:"从〜来看（观察角度）",desc:"表示从某角度观察得出的判断。",appear:6,ex_jp:"私から見て、彼はとても優しい人だ。",ex_read:"わたしから みて、かれは とても やさしい ひとだ。",ex_cn:"从我的角度看，他是个很温柔的人。"},{id:203,level:"n3",pattern:"〜について",meaning:"关于〜",desc:"表示话题或涉及的对象。",appear:8,ex_jp:"日本の文化について調べています。",ex_read:"にほんの ぶんかに ついて しらべています。",ex_cn:"正在调查关于日本的文化。"},{id:204,level:"n3",pattern:"〜を中心に",meaning:"以〜为中心",desc:"表示以某事物为核心展开。",appear:6,ex_jp:"駅を中心に商店街が広がっている。",ex_read:"えきを ちゅうしんに しょうてんがいが ひろがっている。",ex_cn:"以车站为中心，商业街扩展开来。"},{id:205,level:"n3",pattern:"〜向け",meaning:"面向〜的",desc:"表示以某群体或用途为目标对象。",appear:6,ex_jp:"この教材は初心者向けだ。",ex_read:"この きょうざいは しょしんしゃむけだ。",ex_cn:"这个教材是面向初学者的。"},{id:206,level:"n3",pattern:"〜向き",meaning:"适合〜的",desc:"表示某事物适合某类人或用途。",appear:6,ex_jp:"この仕事は体力のある人向きだ。",ex_read:"この しごとは たいりょくの あるひとむきだ。",ex_cn:"这个工作适合有体力的人。"},{id:207,level:"n3",pattern:"〜につれて",meaning:"随着〜",desc:"表示一方的变化引起另一方随之变化。",appear:7,ex_jp:"年を取るにつれて、体力が落ちてきた。",ex_read:"としを とるに つれて、たいりょくが おちてきた。",ex_cn:"随着年龄增长，体力下降了。"},{id:208,level:"n3",pattern:"〜における",meaning:"在〜方面的；在〜中",desc:"限定范围或场景，用于正式场合。",appear:7,ex_jp:"現代社会におけるSNSの役割は大きい。",ex_read:"げんだいしゃかいにおける えすえぬえすの やくわりは おおきい。",ex_cn:"在现代社会中社交媒体的作用很大。"},{id:209,level:"n3",pattern:"〜に当たる",meaning:"相当于〜",desc:"表示某事物与另一事物相当或对应。",appear:5,ex_jp:"日本円で10万円に当たる。",ex_read:"にほんえんで じゅうまんえんに あたる。",ex_cn:"相当于10万日元。"},{id:210,level:"n3",pattern:"〜ずに",meaning:"不〜就；没〜而",desc:"否定形式，表示在不做前项的情况下进行后项。",appear:7,ex_jp:"朝ごはんを食べずに出かけた。",ex_read:"あさごはんを たべずに でかけた。",ex_cn:"没吃早饭就出门了。"},{id:211,level:"n3",pattern:"〜ないで",meaning:"不〜而；请别〜",desc:"表示不做前项转而做后项，或轻度禁止。",appear:7,ex_jp:"ここではタバコを吸わないでください。",ex_read:"ここでは たばこを すわないで ください。",ex_cn:"请不要在这里吸烟。"},{id:212,level:"n3",pattern:"〜なさい",meaning:"请〜（指示/命令）",desc:"用于上对下、长辈对晚辈的指示或命令。",appear:7,ex_jp:"早く寝なさい。",ex_read:"はやく ねなさい。",ex_cn:"快睡吧。"},{id:213,level:"n3",pattern:"〜な（禁止）",meaning:"不许〜；不要〜",desc:"直接禁止对方做某事，语气强烈。",appear:7,ex_jp:"ここに触るな。",ex_read:"ここに さわるな。",ex_cn:"别碰这里！"},{id:214,level:"n3",pattern:"〜のだ/〜んだ",meaning:"（解释说明）是因为〜",desc:"用于说明事由、强调或解释背景。",appear:9,ex_jp:"実は昨日、病気だったのだ。",ex_read:"じつは きのう、びょうきだったのだ。",ex_cn:"其实是因为昨天生病了。"},{id:215,level:"n3",pattern:"〜ように/〜ような",meaning:"像〜那样；为了〜",desc:"表示目的、比喻、示例或希望。",appear:8,ex_jp:"彼のように日本語が上手になりたい。",ex_read:"かれの ように にほんごが じょうずに なりたい。",ex_cn:"想像他那样日语变好。"},{id:216,level:"n3",pattern:"〜みたいだ",meaning:"像〜一样；好像",desc:"表示比喻或不确切的判断，比ようだ更口语化。",appear:7,ex_jp:"彼は日本人みたいに日本語が上手だ。",ex_read:"かれは にほんじん みたいに にほんごが じょうずだ。",ex_cn:"他像日本人一样日语很好。"},{id:217,level:"n3",pattern:"〜っぽい",meaning:"有〜倾向；有点〜",desc:"表示倾向或特征，多用于口语。",appear:6,ex_jp:"彼は忘れっぽい性格だ。",ex_read:"かれは わすれっぽい せいかくだ。",ex_cn:"他是那种容易忘事的性格。"},{id:218,level:"n3",pattern:"〜を通じて/〜を通して",meaning:"通过〜；在整个〜期间",desc:"表示媒介、手段或时间跨度。",appear:6,ex_jp:"友人を通じて彼と知り合った。",ex_read:"ゆうじんを つうじて かれと しりあった。",ex_cn:"通过朋友认识了他。"},{id:219,level:"n3",pattern:"〜を元に",meaning:"以〜为基础",desc:"表示以某事物为素材或依据。",appear:6,ex_jp:"実際の事件を元に映画を作った。",ex_read:"じっさいの じけんを もとに えいがを つくった。",ex_cn:"以真实事件为基础拍了电影。"},{id:220,level:"n3",pattern:"〜にとって",meaning:"对〜来说",desc:"表示从某人或某事物的立场来看。",appear:8,ex_jp:"私にとって、家族が一番大切だ。",ex_read:"わたしにとって、かぞくが いちばん たいせつだ。",ex_cn:"对我来说，家人最重要。"},{id:221,level:"n3",pattern:"〜に沿って",meaning:"按照〜；沿着〜",desc:"表示不偏离某路线、方针或规则。",appear:6,ex_jp:"計画に沿って進めてください。",ex_read:"けいかくに そって すすめてください。",ex_cn:"请按照计划推进。"},{id:222,level:"n3",pattern:"〜を込めて",meaning:"倾注〜；带着〜（情感）",desc:"表示带着某种感情去做某事。",appear:5,ex_jp:"感謝の気持ちを込めて手紙を書いた。",ex_read:"かんしゃの きもちを こめて てがみを かいた。",ex_cn:"带着感谢之情写了信。"},{id:223,level:"n3",pattern:"〜たびに",meaning:"每次〜",desc:"表示每次做前项都出现后项的结果。",appear:6,ex_jp:"彼に会うたびに、新しい発見がある。",ex_read:"かれに あうたびに、あたらしい はっけんが ある。",ex_cn:"每次见到他都有新的发现。"},{id:224,level:"n3",pattern:"〜おきに",meaning:"每隔〜",desc:"表示一定的间隔做某事。",appear:5,ex_jp:"2日おきに植物に水をやる。",ex_read:"ふつかおきに しょくぶつに みずを やる。",ex_cn:"每隔两天给植物浇水。"},{id:225,level:"n3",pattern:"〜ずつ",meaning:"每〜（均等分配）",desc:"表示等量分配或同等程度的重复。",appear:6,ex_jp:"一人に三つずつ配ってください。",ex_read:"ひとりに みっつずつ くばってください。",ex_cn:"请每人分三个。"},{id:226,level:"n3",pattern:"〜かどうか",meaning:"是否〜",desc:"表示两者选一的选择性疑问。",appear:8,ex_jp:"行けるかどうかまだわからない。",ex_read:"いけるか どうか まだ わからない。",ex_cn:"还不知道能不能去。"},{id:227,level:"n3",pattern:"〜際/〜際に",meaning:"当〜之际；〜的时候",desc:"比とき更正式，用于书面或礼貌场合。",appear:6,ex_jp:"ご利用の際は、注意事項をお読みください。",ex_read:"ごりようの さいは、ちゅういじこうを およみください。",ex_cn:"使用时请阅读注意事项。"},{id:228,level:"n3",pattern:"〜最中",meaning:"正在〜的时候",desc:"强调动作正在进行的时间点，带有被打断的语境。",appear:6,ex_jp:"会議の最中に電話が鳴った。",ex_read:"かいぎの さいちゅうに でんわが なった。",ex_cn:"正在开会时电话响了。"},{id:229,level:"n3",pattern:"〜場合",meaning:"〜的时候（假设情况）",desc:"表示在某种情况或条件下。",appear:7,ex_jp:"火事の場合、このドアを開けてください。",ex_read:"かじの ばあい、この どあを あけてください。",ex_cn:"发生火灾时，请打开这扇门。"},{id:230,level:"n3",pattern:"〜から〜にかけて",meaning:"从〜到〜（跨时间/空间）",desc:"表示跨越一定的时间或空间范围。",appear:6,ex_jp:"秋から冬にかけて紅葉が美しい。",ex_read:"あきから ふゆに かけて こうようが うつくしい。",ex_cn:"从秋天到冬天期间红叶很美。"},{id:231,level:"n3",pattern:"〜上で",meaning:"在〜基础上；在〜之后",desc:"表示先做前项再在此基础上进行后项。",appear:7,ex_jp:"よく考えた上で返事します。",ex_read:"よく かんがえた うえで へんじします。",ex_cn:"仔细考虑后再回复。"},{id:232,level:"n3",pattern:"〜上は",meaning:"既然〜就",desc:"表示既然决定了或做了前项，就应全力做后项。",appear:5,ex_jp:"約束した上は、守らなければならない。",ex_read:"やくそくした うえは、まもらなければならない。",ex_cn:"既然约定了，就必须遵守。"},{id:233,level:"n3",pattern:"〜がる",meaning:"表现出〜的样子",desc:"表示第三人称的情感或感受。",appear:6,ex_jp:"子供は新しいおもちゃを欲しがっている。",ex_read:"こどもは あたらしい おもちゃを ほしがっている。",ex_cn:"孩子表现出想要新玩具的样子。"},{id:234,level:"n3",pattern:"〜げ",meaning:"看起来〜；〜的样子",desc:"接形容词或动词连用形，表示从外表看出的神态。",appear:5,ex_jp:"彼は寂しげに窓の外を見ていた。",ex_read:"かれは さびしげに まどのそとを みていた。",ex_cn:"他寂寞地看着窗外。"},{id:235,level:"n3",pattern:"〜てください",meaning:"请〜",desc:"请求对方做某事。",appear:10,ex_jp:"ここに名前を書いてください。",ex_read:"ここに なまえを かいてください。",ex_cn:"请在这里写上名字。"},{id:236,level:"n3",pattern:"〜ちゃう/〜とく",meaning:"（口语缩略）〜掉了/先〜好",desc:"ちゃう＝てしまう的口语形；とく＝ておく的口语形。",appear:7,ex_jp:"宿題、やっちゃったよ。先に言っといた。",ex_read:"しゅくだい、やっちゃったよ。さきに いっとく。",ex_cn:"作业做完了哦。我先说好了。"},{id:237,level:"n3",pattern:"〜というのは",meaning:"所谓〜就是",desc:"用于下定义或说明某事物的概念。",appear:6,ex_jp:"「花見」というのは、桜を見て楽しむことだ。",ex_read:"「はなみ」というのは、さくらを みて たのしむことだ。",ex_cn:"所谓赏花，就是观赏樱花享受乐趣。"},{id:238,level:"n3",pattern:"〜なんか/〜なんて",meaning:"〜之类；〜什么的",desc:"用于列举自谦或轻视的事物，语气随意。",appear:7,ex_jp:"私なんかにはできません。",ex_read:"わたし なんかには できません。",ex_cn:"像我这样的人做不到。"},{id:239,level:"n3",pattern:"〜というと",meaning:"说到〜；提起〜",desc:"用于引出话题或说明。",appear:6,ex_jp:"日本料理というと、寿司が思い浮かぶ。",ex_read:"にほんりょうりと いうと、すしが おもいうかぶ。",ex_cn:"说到日本料理，就会想到寿司。"},{id:240,level:"n3",pattern:"〜として",meaning:"作为〜",desc:"表示身份、资格或立场。",appear:8,ex_jp:"趣味として日本語を勉強している。",ex_read:"しゅみとして にほんごを べんきょうしている。",ex_cn:"作为爱好在学习日语。"},{id:241,level:"n3",pattern:"〜なんて",meaning:"竟然〜；〜这种事",desc:"表示意外、轻视或感叹。",appear:6,ex_jp:"彼が合格するなんて信じられない。",ex_read:"かれが ごうかくするなんて しんじられない。",ex_cn:"他竟然合格了，真不敢相信。"},{id:242,level:"n3",pattern:"〜というより",meaning:"与其说〜不如说",desc:"表示更正前项，提出更恰当的表达。",appear:6,ex_jp:"彼は教師というより、学者だ。",ex_read:"かれは きょうしと いうより、がくしゃだ。",ex_cn:"与其说他是教师，不如说是学者。"},{id:243,level:"n3",pattern:"〜からには",meaning:"既然〜就",desc:"表示既然做了前项的决定或行为，就应承担相应责任。",appear:6,ex_jp:"約束したからには、守るべきだ。",ex_read:"やくそくした からには、まもるべきだ。",ex_cn:"既然约定了，就应该遵守。"},{id:244,level:"n3",pattern:"〜に違いない",meaning:"一定〜",desc:"表示很有把握的推测。",appear:7,ex_jp:"彼はもう着いたに違いない。",ex_read:"かれは もう ついたに ちがいない。",ex_cn:"他一定已经到了。"},{id:245,level:"n3",pattern:"〜か〜ないかのうちに",meaning:"刚一〜就〜",desc:"前项动作还没完全完成，后项就发生了。",appear:5,ex_jp:"家に着くか着かないかのうちに、雨が降り出した。",ex_read:"いえに つくか つかないかの うちに、あめが ふりだした。",ex_cn:"刚到家就下起雨来了。"},{id:246,level:"n3",pattern:"〜ついでに",meaning:"顺便〜",desc:"趁着做前项的机会顺便做后项。",appear:6,ex_jp:"買い物のついでに、郵便局に寄った。",ex_read:"かいものの ついでに、ゆうびんきょくに よった。",ex_cn:"买东西时顺便去了趟邮局。"},{id:247,level:"n3",pattern:"〜ほど（程度）",meaning:"〜得（程度）",desc:"表示程度高，大到影响了其他。",appear:7,ex_jp:"彼は忙しくて寝る時間もないほどだ。",ex_read:"かれは いそがしくて ねるじかんも ないほどだ。",ex_cn:"他忙得连睡觉的时间都没有。"},{id:248,level:"n3",pattern:"〜ことに（は）",meaning:"〜的是（评价）",desc:"用于情感形容词前，表示说话人的情感评价。",appear:6,ex_jp:"不思議なことに、彼はその話を知らなかった。",ex_read:"ふしぎなことに、かれは そのはなしを しらなかった。",ex_cn:"奇怪的是，他不知道那件事。"},{id:249,level:"n3",pattern:"〜ものです",meaning:"（感叹/感慨）真是〜",desc:"表示感叹、感慨或自然规律。",appear:6,ex_jp:"時間が経つのは早いものだ。",ex_read:"じかんが たつの は はやいものだ。",ex_cn:"时间过得真快啊。"},{id:250,level:"n3",pattern:"〜ものか",meaning:"怎么会〜（强烈否定）",desc:"表示强烈的否定或反问。",appear:5,ex_jp:"そんなこと、するものか。",ex_read:"そんなこと、するものか。",ex_cn:"那种事，我怎么可能做！"},{id:251,level:"n3",pattern:"〜ないことはない",meaning:"也不是不〜",desc:"双重否定，表示不完全否定。",appear:5,ex_jp:"行きたくないことはないけど、ちょっと疲れた。",ex_read:"いきたくないことは ないけど、ちょっと つかれた。",ex_cn:"也不是不想去，只是有点累了。"},{id:252,level:"n3",pattern:"〜てくる",meaning:"（方向性）〜过来；逐渐变得〜",desc:"表示动作由远及近、变化从过去到现在的趋势。",appear:9,ex_jp:"最近、日本語が上手になってきた。",ex_read:"さいきん、にほんごが じょうずに なってきた。",ex_cn:"最近日语渐渐变好了。"},{id:253,level:"n3",pattern:"〜ていく",meaning:"（方向性）〜过去；逐渐变得〜",desc:"表示动作由近及远、变化从现在到将来的趋势。",appear:8,ex_jp:"これからも頑張っていきます。",ex_read:"これからも がんばって いきます。",ex_cn:"今后也会继续努力下去。"},{id:254,level:"n3",pattern:"〜てある",meaning:"（状态）已经〜好了",desc:"表示某人为了某目的而做的动作结果状态。",appear:7,ex_jp:"窓が開けてある。",ex_read:"まどが あけてある。",ex_cn:"窗户开着（有人特意开的）。"},{id:255,level:"n3",pattern:"〜ておく",meaning:"预先〜好",desc:"表示提前做好准备或让状态保持下去。",appear:7,ex_jp:"後で使うから、ここに置いておいて。",ex_read:"あとで つかうから、ここに おいておいて。",ex_cn:"之后要用，先放这里吧。"},{id:256,level:"n3",pattern:"〜てみる",meaning:"试着〜",desc:"表示尝试做某事。",appear:8,ex_jp:"一度食べてみてください。",ex_read:"いちど たべて みてください。",ex_cn:"请吃一次看看。"},{id:257,level:"n3",pattern:"〜てほしい",meaning:"希望（某人）〜",desc:"表示希望对方做某事。",appear:6,ex_jp:"日本語で話してほしい。",ex_read:"にほんごで はなしてほしい。",ex_cn:"希望你能用日语说。"},{id:258,level:"n3",pattern:"〜なくてはならない",meaning:"必须〜",desc:"与なければならない同义，稍口语化。",appear:7,ex_jp:"明日は早起きしなくてはならない。",ex_read:"あしたは はやおきしなくては ならない。",ex_cn:"明天必须早起。"},{id:259,level:"n3",pattern:"〜てはいられない",meaning:"不能一直〜",desc:"表示不能继续以某状态存在或做某事。",appear:6,ex_jp:"のんびりしてはいられない。",ex_read:"のんびりしては いられない。",ex_cn:"不能一直悠闲下去了。"},{id:260,level:"n3",pattern:"〜させる",meaning:"让〜做；使〜",desc:"使役形，表示让某人做某事或导致某结果。",appear:8,ex_jp:"先生が学生に本を読ませた。",ex_read:"せんせいが がくせいに ほんを よませた。",ex_cn:"老师让学生读书。"},{id:261,level:"n3",pattern:"〜られる",meaning:"被〜；能〜；自动〜",desc:"被动、可能或自发。",appear:9,ex_jp:"私は友達に褒められた。",ex_read:"わたしは ともだちに ほめられた。",ex_cn:"我被朋友表扬了。"},{id:262,level:"n3",pattern:"〜させられる",meaning:"被迫〜",desc:"使役被动形，表示被迫做或不得不做。",appear:5,ex_jp:"たくさんの宿題をさせられた。",ex_read:"たくさんの しゅくだいを させられた。",ex_cn:"被迫做了很多作业。"},{id:263,level:"n3",pattern:"〜たらどう/〜てはどう",meaning:"〜怎么样（建议）",desc:"用于提出建议或劝诱。",appear:6,ex_jp:"一度先生に相談したらどうですか。",ex_read:"いちど せんせいに そうだんしたら どうですか。",ex_cn:"找老师商量一下怎么样？"},{id:264,level:"n3",pattern:"〜も〜ば〜も",meaning:"既〜又〜",desc:"表示并列两个事物或状态。",appear:6,ex_jp:"彼はお金もあれば、時間もある。",ex_read:"かれは おかねも あれば、じかんも ある。",ex_cn:"他既有钱又有时间。"},{id:265,level:"n3",pattern:"〜恐れがある",meaning:"有〜的担心；恐怕会〜",desc:"表示某种不好的事情可能发生。",appear:6,ex_jp:"今夜、台風が来る恐れがある。",ex_read:"こんや、たいふうが くる おそれがある。",ex_cn:"今晚恐怕会有台风。"},{id:266,level:"n3",pattern:"〜に決まっている",meaning:"一定〜；肯定〜",desc:"表示确信程度很高的推测。",appear:6,ex_jp:"彼は知っているに決まっている。",ex_read:"かれは しっているに きまっている。",ex_cn:"他肯定知道。"},{id:267,level:"n3",pattern:"〜抜きで/〜抜きにして",meaning:"省去〜；不〜",desc:"表示省略或排除某事物。",appear:5,ex_jp:"冗談抜きで、真面目に話そう。",ex_read:"じょうだんぬきで、まじめに はなそう。",ex_cn:"不开玩笑，认真谈吧。"},{id:268,level:"n3",pattern:"〜をきっかけに",meaning:"以〜为契机",desc:"表示某事成为开端或契机。",appear:6,ex_jp:"友達の紹介をきっかけに、彼と知り合った。",ex_read:"ともだちの しょうかいを きっかけに、かれと しりあった。",ex_cn:"以朋友的介绍为契机认识了他。"},{id:269,level:"n3",pattern:"〜に加えて",meaning:"加上〜；不仅〜还",desc:"表示在前项的基础上再附加后项。",appear:6,ex_jp:"雨に加えて風も強くなってきた。",ex_read:"あめに くわえて かぜも つよくなってきた。",ex_cn:"不仅下雨，风也变大了。"},{id:270,level:"n3",pattern:"〜を始め",meaning:"以〜为首；〜以及",desc:"举出代表性事例，暗示还有其他。",appear:6,ex_jp:"社長を始め、社員全員が参加した。",ex_read:"しゃちょうを はじめ、しゃいん ぜんいんが さんかした。",ex_cn:"以社长为始，全体员工都参加了。"},{id:271,level:"n3",pattern:"〜に過ぎない",meaning:"只不过〜",desc:"表示程度低，不过如此。",appear:6,ex_jp:"それはただの噂に過ぎない。",ex_read:"それは ただの うわさに すぎない。",ex_cn:"那只不过是个传闻。"},{id:272,level:"n3",pattern:"〜に限る",meaning:"最好是〜；莫过于",desc:"表示某事物是最佳选择。",appear:6,ex_jp:"疲れた時は寝るに限る。",ex_read:"つかれた ときは ねるに かぎる。",ex_cn:"累了的时候最好是睡觉。"},{id:273,level:"n2",pattern:"〜どころではない",meaning:"不是〜的时候；顾不上",desc:"表示没有余力或心情做某事。",appear:6,ex_jp:"試験前で遊んでいるどころではない。",ex_read:"しけんまえで あそんでいるところではない。",ex_cn:"快考试了，不是玩的时候。"},{id:274,level:"n2",pattern:"〜どころか",meaning:"岂止〜；别说〜就连",desc:"表示不仅不成立前项，后项更强烈地否定。",appear:7,ex_jp:"彼は謝るどころか、笑っていた。",ex_read:"かれは あやまるどころか、わらっていた。",ex_cn:"他别说道歉了，还在笑。"},{id:275,level:"n2",pattern:"〜とは限らない",meaning:"不一定〜；未必",desc:"表示不一定是那样。",appear:7,ex_jp:"高いものが必ずいいとは限らない。",ex_read:"たかいものが かならず いいとは かぎらない。",ex_cn:"贵的东西不一定好。"},{id:276,level:"n2",pattern:"〜ないことはない",meaning:"也不是不〜",desc:"双重否定表示不完全否定。",appear:6,ex_jp:"できないこともないけど、時間がかかる。",ex_read:"できないことも ないけど、じかんが かかる。",ex_cn:"也不是不能做，但费时间。"},{id:277,level:"n2",pattern:"〜ようがない",meaning:"无法〜；没办法〜",desc:"表示想做但方法或手段不存在。",appear:6,ex_jp:"連絡先がわからないから、知らせようがない。",ex_read:"れんらくさきが わからないから、しらせようがない。",ex_cn:"不知道联系方式，所以没法通知。"},{id:278,level:"n2",pattern:"〜にたえない",meaning:"不值得〜；不堪〜",desc:"表示没有价值或无法忍受。",appear:5,ex_jp:"この作品は批判にたえない。",ex_read:"この さくひんは ひはんに たえない。",ex_cn:"这部作品经不起批评。"},{id:279,level:"n2",pattern:"〜にたる",meaning:"值得〜；足以〜",desc:"表示有足够的价值或资格。",appear:5,ex_jp:"彼は信頼するにたる人物だ。",ex_read:"かれは しんらいするに たる じんぶつだ。",ex_cn:"他是个值得信赖的人。"},{id:280,level:"n2",pattern:"〜を踏まえて",meaning:"基于〜；考虑到〜",desc:"表示在前项事实或判断基础上做后项。",appear:6,ex_jp:"以上の結果を踏まえて、今後の計画を立てる。",ex_read:"いじょうの けっかを ふまえて、こんごの けいかくを たてる。",ex_cn:"基于以上结果制定今后的计划。"},{id:281,level:"n2",pattern:"〜を経て",meaning:"经过〜；通过〜",desc:"表示经过某地点或某过程后达到。",appear:5,ex_jp:"面接を経て、採用が決まった。",ex_read:"めんせつを へて、さいようが きまった。",ex_cn:"经过面试，决定录用。"},{id:282,level:"n2",pattern:"〜を皮切りに",meaning:"以〜为开端",desc:"表示以某事为开端，之后同类事件陆续发生。",appear:5,ex_jp:"東京を皮切りに全国ツアーが始まった。",ex_read:"とうきょうを かわきりに ぜんこくつあーが はじまった。",ex_cn:"以东京为开端，开始了全国巡演。"},{id:283,level:"n2",pattern:"〜をよそに",meaning:"不顾〜；不管〜",desc:"表示无视别人的看法或反对做某事。",appear:5,ex_jp:"周囲の反対をよそに、彼は夢を追い続けた。",ex_read:"しゅういの はんたいを よそに、かれは ゆめを おいつづけた。",ex_cn:"不顾周围人的反对，他继续追逐梦想。"},{id:284,level:"n2",pattern:"〜に即して",meaning:"按照〜；根据〜",desc:"表示按照某标准、规则或事实。",appear:5,ex_jp:"法律に即して判断しなければならない。",ex_read:"ほうりつに そくして はんだんしなければならない。",ex_cn:"必须根据法律进行判断。"},{id:285,level:"n2",pattern:"〜に照らして",meaning:"根据〜；鉴于〜",desc:"表示以某标准或法律为基准进行判断。",appear:5,ex_jp:"規則に照らして処分を決める。",ex_read:"きそくに てらして しょぶんを きめる。",ex_cn:"根据规则决定处分。"},{id:286,level:"n2",pattern:"〜にひきかえ",meaning:"与〜相反",desc:"表示前后对比，后项与前项形成对照。",appear:5,ex_jp:"兄にひきかえ、弟はとても静かだ。",ex_read:"あにに ひきかえ、おとうとは とても しずかだ。",ex_cn:"与哥哥相反，弟弟很安静。"},{id:287,level:"n2",pattern:"〜に代えて",meaning:"代替〜",desc:"表示用后项代替前项。",appear:5,ex_jp:"挨拶に代えて、感謝の言葉を述べた。",ex_read:"あいさつに かえて、かんしゃの ことばを のべた。",ex_cn:"代替问候，表达了感谢。"},{id:288,level:"n2",pattern:"〜にこたえて",meaning:"响应〜；应〜要求",desc:"表示回应某人的期待、要求或号召。",appear:5,ex_jp:"皆さんのご期待にこたえて、頑張ります。",ex_read:"みなさんの ごきたいに こたえて、がんばります。",ex_cn:"不负大家的期望，我会努力的。"},{id:289,level:"n2",pattern:"〜に先立ち",meaning:"在〜之前",desc:"比にあたって更正式，多用于书面或演讲。",appear:5,ex_jp:"会議に先立ち、簡単な説明をします。",ex_read:"かいぎに さきだち、かんたんな せつめいを します。",ex_cn:"在会议之前，先做一个简单的说明。"},{id:290,level:"n2",pattern:"〜に臨んで",meaning:"面临〜；在〜之际",desc:"表示面对某事（常为重要场合）之时。",appear:5,ex_jp:"試験に臨んで、緊張している。",ex_read:"しけんに のぞんで、きんちょうしている。",ex_cn:"面临考试，很紧张。"},{id:291,level:"n2",pattern:"〜ない限り",meaning:"除非〜否则不",desc:"表示前项条件是后项成立的唯一例外。",appear:7,ex_jp:"雨が降らない限り、試合は行う。",ex_read:"あめが ふらないかぎり、しあいは おこなう。",ex_cn:"除非下雨，否则比赛照常进行。"},{id:292,level:"n2",pattern:"〜ないことには",meaning:"如果不〜就不",desc:"表示前项是后项的前提条件。",appear:6,ex_jp:"実際に見ないことには、良さがわからない。",ex_read:"じっさいに みないことには、よさが わからない。",ex_cn:"不实际看看就不知道好在哪。"},{id:293,level:"n2",pattern:"〜なくしては",meaning:"如果没有〜就不能",desc:"表示前项是必不可少的前提。",appear:5,ex_jp:"努力なくしては成功はない。",ex_read:"どりょくなくしては せいこうは ない。",ex_cn:"没有努力就没有成功。"},{id:294,level:"n2",pattern:"〜ながらも",meaning:"虽然〜但是",desc:"表示转折，比ながら的逆接语气更强。",appear:6,ex_jp:"狭いながらも、楽しい家だ。",ex_read:"せまいながらも、たのしい いえだ。",ex_cn:"虽然狭小，但很快乐的家。"},{id:295,level:"n2",pattern:"〜ばかりに",meaning:"就因为〜（导致不良结果）",desc:"表示前项是后项不利结果的原因。",appear:6,ex_jp:"一言余計なことを言ったばかりに、怒らせてしまった。",ex_read:"ひとこと よけいなことを いったばかりに、おこらせてしまった。",ex_cn:"就因为多说了一句话，惹人生气了。"},{id:296,level:"n2",pattern:"〜まい",meaning:"（否定意志/推测）不会〜吧",desc:"表示否定意志或否定的推测。",appear:6,ex_jp:"彼はそんなことは言うまい。",ex_read:"かれは そんなことは いうまい。",ex_cn:"他应该不会说那种话吧。"},{id:297,level:"n2",pattern:"〜まみれ",meaning:"满是〜（附着物）",desc:"指表面沾满脏东西，多用于负面。",appear:5,ex_jp:"汗まみれになって働いた。",ex_read:"あせまみれに なって はたらいた。",ex_cn:"满身是汗地工作。"},{id:298,level:"n2",pattern:"〜もさることながら",meaning:"〜自不必说、〜也是",desc:"表示前项固然如此，后项也同样突出。",appear:5,ex_jp:"実力もさることながら、人柄も素晴らしい。",ex_read:"じつりょくも さることながら、ひとがらも すばらしい。",ex_cn:"实力自不必说，人品也很好。"},{id:299,level:"n2",pattern:"〜ものを",meaning:"（遗憾/不满）明明〜却",desc:"表示对未能实现的事情感到遗憾或不满。",appear:5,ex_jp:"知らせてくれれば行ったものを。",ex_read:"しらせてくれれば いったものを。",ex_cn:"要是通知我的话我就去了（真遗憾）。"},{id:300,level:"n2",pattern:"〜や/〜や否や",meaning:"刚一〜就",desc:"书面语，表示前项动作完成后立即发生后项。",appear:5,ex_jp:"ベルが鳴るや否や、子供たちは飛び出した。",ex_read:"べるが なるや いなや、こどもたちは とびだした。",ex_cn:"铃声一响，孩子们就冲了出去。"},{id:301,level:"n2",pattern:"〜を余儀なくされる",meaning:"被迫〜",desc:"表示被形势所迫不得不做某事。",appear:5,ex_jp:"台風のため、中止を余儀なくされた。",ex_read:"たいふうのため、ちゅうしを よぎなくされた。",ex_cn:"因台风被迫中止。"},{id:302,level:"n2",pattern:"〜を余儀なくさせる",meaning:"迫使〜",desc:"表示使某人陷入不得不做的状况。",appear:5,ex_jp:"不況が多くの企業を倒産を余儀なくさせた。",ex_read:"ふきょうが おおくの きぎょうを とうさんを よぎなくさせた。",ex_cn:"不景气迫使许多企业倒闭。"},{id:303,level:"n2",pattern:"〜かたがた",meaning:"顺便；兼带",desc:"书面语，表示借做前项的机会做后项。",appear:4,ex_jp:"お礼かたがた、ご報告に伺いました。",ex_read:"おれいかたがた、ごほうこくに うかがいました。",ex_cn:"顺便道谢，前来报告。"},{id:304,level:"n2",pattern:"〜かたわら",meaning:"一边〜一边；在〜的同时",desc:"表示在做主要活动的同时也做另一件事。",appear:5,ex_jp:"会社勤めのかたわら、小説を書いている。",ex_read:"かいしゃづとめの かたわら、しょうせつを かいている。",ex_cn:"一边在公司上班，一边写小说。"},{id:305,level:"n2",pattern:"〜がてら",meaning:"顺便〜",desc:"表示做前项的同时顺便做后项。",appear:5,ex_jp:"散歩がてら、コンビニに行ってきた。",ex_read:"さんぽがてら、こんびにに いってきた。",ex_cn:"散步顺便去了趟便利店。"},{id:306,level:"n2",pattern:"〜きらいがある",meaning:"有〜的倾向（负面）",desc:"表示某种不好的倾向或缺点。",appear:4,ex_jp:"人間は楽な方に流れやすいきらいがある。",ex_read:"にんげんは らくなほうに ながれやすい きらいがある。",ex_cn:"人往往有倾向于安逸的毛病。"},{id:307,level:"n2",pattern:"〜ごとき",meaning:"像〜这种的（轻蔑）",desc:"表示轻蔑或自谦的语气。",appear:5,ex_jp:"私ごときがお役に立てるでしょうか。",ex_read:"わたしごときが おやくに たてるでしょうか。",ex_cn:"像我这样的人能帮上忙吗。"},{id:308,level:"n2",pattern:"〜すら",meaning:"连〜都",desc:"表示极端事例，和さえ类似。",appear:5,ex_jp:"彼は自分の名前すら忘れてしまった。",ex_read:"かれは じぶんの なまえすら わすれてしまった。",ex_cn:"他连自己的名字都忘了。"},{id:309,level:"n2",pattern:"〜ただ〜のみ",meaning:"只〜；唯〜",desc:"书面语，表示仅限于此。",appear:4,ex_jp:"後は結果を待つのみだ。",ex_read:"あとは けっかを まつのみだ。",ex_cn:"之后唯有等待结果。"},{id:310,level:"n2",pattern:"〜たはしから",meaning:"刚〜就（反复）",desc:"表示刚做完前项又变成同一状态，常用于不满。",appear:4,ex_jp:"覚えたはしから忘れていく。",ex_read:"おぼえたはしから わすれていく。",ex_cn:"刚记就忘。"},{id:311,level:"n2",pattern:"〜たも同然",meaning:"与做了～一样",desc:"表示几乎等同于某状态。",appear:5,ex_jp:"完成したも同然だ。",ex_read:"かんせいしたも どうぜんだ。",ex_cn:"几乎等于完成了。"},{id:312,level:"n2",pattern:"〜つつも",meaning:"虽然〜但是",desc:"表示逆接，比ながらも更正式。",appear:5,ex_jp:"悪いと知りつつも、嘘をついてしまった。",ex_read:"わるいと しりつつも、うそを ついてしまった。",ex_cn:"明知不对，还是撒了谎。"},{id:313,level:"n2",pattern:"〜てからでないと",meaning:"不先〜就不能",desc:"强调必须先做前项后才能做后项。",appear:5,ex_jp:"詳細を聞いてからでないと、返事できない。",ex_read:"しょうさいを きいてからでないと、へんじできない。",ex_cn:"不先听详细情况就无法回复。"},{id:314,level:"n2",pattern:"〜てからというもの",meaning:"自从〜以后",desc:"表示以某事为转折点，情况发生变化。",appear:5,ex_jp:"彼が来てからというもの、雰囲気が明るくなった。",ex_read:"かれが きてからというもの、ふんいきが あかるくなった。",ex_cn:"自从他来了以后，气氛变得明亮了。"},{id:315,level:"n2",pattern:"〜てはならない",meaning:"不能〜；不应该〜",desc:"表示禁止或强烈劝阻。",appear:6,ex_jp:"このことを他人に話してはならない。",ex_read:"このことを たにんに はなしてはならない。",ex_cn:"这件事不能跟别人说。"},{id:316,level:"n2",pattern:"〜ということだ",meaning:"据说～；也就是说",desc:"表示传闻或对前述进行总结。",appear:7,ex_jp:"彼は来月結婚するということだ。",ex_read:"かれは らいげつ けっこんするという ことだ。",ex_cn:"听说他下个月结婚。"},{id:317,level:"n2",pattern:"〜といったらない",meaning:"〜得不得了；无法形容",desc:"表示程度极高，无法用语言描述。",appear:5,ex_jp:"彼の驚いた顔といったらなかった。",ex_read:"かれの おどろいた かおと いったらなかった。",ex_cn:"他那惊讶的表情真是无法形容。"},{id:318,level:"n2",pattern:"〜と思いきや",meaning:"原以为〜却",desc:"表示与预想相反的结果。",appear:4,ex_jp:"来ると思いきや、結局来なかった。",ex_read:"くると おもいきや、けっきょく こなかった。",ex_cn:"我以为他会来，结果没来。"},{id:319,level:"n2",pattern:"〜とあって",meaning:"因为〜（缘故）",desc:"表示由于特殊情况而自然产生后项。",appear:5,ex_jp:"休日とあって、どこも人でいっぱいだ。",ex_read:"きゅうじつと あって、どこも ひとで いっぱいだ。",ex_cn:"因为是假日，到处挤满了人。"},{id:320,level:"n2",pattern:"〜とあれば",meaning:"如果是〜的话（就会）",desc:"表示在某种特殊情况下会采取行动。",appear:5,ex_jp:"必要とあれば、いつでも手伝います。",ex_read:"ひつようと あれば、いつでも てつだいます。",ex_cn:"如果需要的话，随时帮忙。"},{id:321,level:"n2",pattern:"〜となると/〜となれば",meaning:"要是〜的话；提到〜",desc:"表示一旦涉及某话题或条件。",appear:6,ex_jp:"海外旅行となると、準備が大変だ。",ex_read:"かいがいりょこうと なると、じゅんびが たいへんだ。",ex_cn:"一说到出国旅游，准备就很麻烦。"},{id:322,level:"n2",pattern:"〜と相まって",meaning:"与〜相结合",desc:"表示两个因素相互作用产生了更强效果。",appear:4,ex_jp:"美しい景色と相まって、最高の時間だった。",ex_read:"うつくしい けしきと あいまって、さいこうの じかんだった。",ex_cn:"加上美丽的景色，度过了最美好的时光。"},{id:323,level:"n2",pattern:"〜ところを",meaning:"在〜的时候（被打断）",desc:"表示在某种情况下被打扰或得到帮助。",appear:5,ex_jp:"お忙しいところをすみません。",ex_read:"おいそがしい ところを すみません。",ex_cn:"在您忙碌的时候打扰了，抱歉。"},{id:324,level:"n2",pattern:"〜とはいえ",meaning:"虽说〜但是",desc:"表示客观事实上的转折。",appear:5,ex_jp:"春とはいえ、まだ寒い日がある。",ex_read:"はるとは いえ、まだ さむいひが ある。",ex_cn:"虽说是春天，但还有寒冷的日子。"},{id:325,level:"n2",pattern:"〜ないではすまない",meaning:"不〜的话不行",desc:"表示如果不做某事后就不能了结。",appear:4,ex_jp:"謝らないではすまないだろう。",ex_read:"あやまらないでは すまないだろう。",ex_cn:"不道歉的话恐怕不行。"},{id:326,level:"n2",pattern:"〜なり（〜するなり）",meaning:"刚一〜就（立即）",desc:"表示前项动作一完成，紧接着就发生后项。",appear:5,ex_jp:"彼は家に帰るなり、部屋に閉じこもった。",ex_read:"かれは いえに かえるなり、へやに とじこもった。",ex_cn:"他一回到家就躲进了房间。"},{id:327,level:"n2",pattern:"〜にして",meaning:"在〜时候/阶段；作为",desc:"表示时间点、身份或并列。",appear:6,ex_jp:"30歳にして、初めて海外に行った。",ex_read:"さんじゅっさいにして、はじめて かいがいに いった。",ex_cn:"30岁时第一次去了国外。"},{id:328,level:"n2",pattern:"〜にしては",meaning:"作为〜来说算是",desc:"表示后项结果与前项一般标准不符。",appear:6,ex_jp:"初心者にしては上手だ。",ex_read:"しょしんしゃに しては じょうずだ。",ex_cn:"作为新手来说算是很不错了。"},{id:329,level:"n2",pattern:"〜にしろ/〜にせよ",meaning:"无论〜；就算〜",desc:"表示让步或并列列举。",appear:6,ex_jp:"賛成するにしろ、反対するにしろ、意見を聞かせてください。",ex_read:"さんせいするにしろ、はんたいするにしろ、いけんを きかせてください。",ex_cn:"无论赞成还是反对，请告诉我你的意见。"},{id:330,level:"n2",pattern:"〜につけ",meaning:"每当〜就；无论是〜还是",desc:"表示每当看到或想到前项就会出现后项情感。",appear:5,ex_jp:"彼女の写真を見るにつけ、その日を思い出す。",ex_read:"かのじょの しゃしんを みるにつけ、そのひを おもいだす。",ex_cn:"每次看到她的照片，就会想起那天。"},{id:331,level:"n2",pattern:"〜にもほどがある",meaning:"〜也要有个限度",desc:"表示对过分行为的不满或批评。",appear:4,ex_jp:"いたずらにもほどがある。",ex_read:"いたずらにも ほどが ある。",ex_cn:"恶作剧也要有个限度。"},{id:332,level:"n2",pattern:"〜の極み",meaning:"〜的极致；极其〜",desc:"表示程度达到顶点。",appear:4,ex_jp:"感激の極みです。",ex_read:"かんげきの きわみです。",ex_cn:"感激至极。"},{id:333,level:"n2",pattern:"〜のもとで",meaning:"在〜之下（条件/指导）",desc:"表示在某人的指导、影响或条件下。",appear:5,ex_jp:"先生のもとで研究を続けている。",ex_read:"せんせいの もとで けんきゅうを つづけている。",ex_cn:"在老师的指导下继续研究。"},{id:334,level:"n2",pattern:"〜ばこそ",meaning:"正因为〜才",desc:"强调前项是后项不可或缺的原因。",appear:5,ex_jp:"努力すればこそ、成功できるのだ。",ex_read:"どりょくすればこそ、せいこうできるのだ。",ex_cn:"正因为努力，才能成功。"},{id:335,level:"n2",pattern:"〜はおろか",meaning:"别说〜就连〜也",desc:"表示前项当然不成立，后项更不可能。",appear:5,ex_jp:"漢字はおろか、ひらがなも書けない。",ex_read:"かんじは おろか、ひらがなも かけない。",ex_cn:"别说汉字，连平假名都不会写。"},{id:336,level:"n2",pattern:"〜はさておき",meaning:"暂且不表；先放一边",desc:"表示先把某话题放一边，先处理主要的。",appear:5,ex_jp:"結果はさておき、まず挑戦することが大切だ。",ex_read:"けっかは さておき、まず ちょうせんすることが たいせつだ。",ex_cn:"结果暂且不说，首先挑战本身很重要。"},{id:337,level:"n2",pattern:"〜ばかりになっている",meaning:"只差〜；眼看就要",desc:"表示某事即将发生，只差最后一步。",appear:5,ex_jp:"飛行機は離陸するばかりになっている。",ex_read:"ひこうきは りりくする ばかりに なっている。",ex_cn:"飞机眼看就要起飞了。"},{id:338,level:"n2",pattern:"〜までもない/〜までのこともない",meaning:"没必要〜",desc:"表示没有必要做到某程度。",appear:5,ex_jp:"わざわざ行くまでもない。",ex_read:"わざわざ いくまでもない。",ex_cn:"没必要特意去一趟。"},{id:339,level:"n2",pattern:"〜めく",meaning:"带有〜气息；显得〜",desc:"表示某种状态或样子。",appear:4,ex_jp:"春めいてきた。",ex_read:"はるめいて きた。",ex_cn:"春天的气息渐浓。"},{id:340,level:"n2",pattern:"〜ゆえ/ゆえに",meaning:"因为〜（书面）",desc:"书面语，表示原因理由。",appear:5,ex_jp:"女性であるがゆえに、不利益を被ることがある。",ex_read:"じょせいで あるがゆえに、ふりえきを こうむることがある。",ex_cn:"因为是女性，有时会受到不公平待遇。"},{id:341,level:"n2",pattern:"〜を禁じ得ない",meaning:"不禁〜；忍不住",desc:"表示无法抑制某种情感。",appear:5,ex_jp:"彼の無事を知り、涙を禁じ得なかった。",ex_read:"かれの ぶじを しり、なみだを きんじえなかった。",ex_cn:"得知他平安无事，不禁流下了眼泪。"},{id:342,level:"n2",pattern:"〜を境に",meaning:"以〜为界",desc:"表示以某事件为分界线，前后状况发生了变化。",appear:5,ex_jp:"あの事件を境に、彼は変わってしまった。",ex_read:"あの じけんを さかいに、かれは かわってしまった。",ex_cn:"以那件事为界，他变了。"},{id:343,level:"n2",pattern:"〜をものともせずに",meaning:"不顾〜；不把〜当回事",desc:"表示不把困难或反对意见放在眼里。",appear:5,ex_jp:"彼は批判をものともせずに、自分の信念を貫いた。",ex_read:"かれは ひはんを ものともせずに、じぶんの しんねんを つらぬいた。",ex_cn:"他不顾批判，贯彻了自己的信念。"},{id:344,level:"n2",pattern:"〜ないではいられない",meaning:"忍不住〜；不能不",desc:"表示无法抑制某种情绪或行为冲动。",appear:5,ex_jp:"彼の話を聞いて、笑わないではいられなかった。",ex_read:"かれの はなしを きいて、わらわないでは いられなかった。",ex_cn:"听了他的话，忍不住笑了出来。"},{id:345,level:"n2",pattern:"〜を目指して",meaning:"以〜为目标",desc:"表示朝着目标努力前进。",appear:6,ex_jp:"合格を目指して、毎日勉強している。",ex_read:"ごうかくを めざして、まいにち べんきょうしている。",ex_cn:"以合格为目标，每天努力学习。"},{id:346,level:"n2",pattern:"〜を対象に",meaning:"以〜为对象",desc:"表示把某事或某人作为对象。",appear:5,ex_jp:"小学生を対象に、アンケート調査を行った。",ex_read:"しょうがくせいを たいしょうに、あんけーとちょうさを おこなった。",ex_cn:"以小学生为对象进行了问卷调查。"},{id:347,level:"n2",pattern:"〜に即応して",meaning:"相应；即时应对",desc:"表示能够迅速适应或应对。",appear:4,ex_jp:"状況に即応して、対応策を考える。",ex_read:"じょうきょうに そくおうして、たいおうさくを かんがえる。",ex_cn:"根据情况迅速考虑对策。"},{id:348,level:"n2",pattern:"〜に至る",meaning:"达到〜；导致〜",desc:"表示经过过程后达到某结果或状态。",appear:5,ex_jp:"両者の話し合いは決裂に至った。",ex_read:"りょうしゃの はなしあいは けつれつに いたった。",ex_cn:"双方的谈判最终导致破裂。"},{id:349,level:"n2",pattern:"〜を限りに",meaning:"以〜为最后；尽最大",desc:"表示以某时间为截止，或尽全力做某事。",appear:4,ex_jp:"今日を限りに、タバコをやめる。",ex_read:"きょうを かぎりに、たばこを やめる。",ex_cn:"以今天为界，戒烟。"},{id:350,level:"n2",pattern:"〜を兼ねて",meaning:"兼做〜；也作为",desc:"表示一个行为同时兼具两个目的。",appear:5,ex_jp:"運動を兼ねて、歩いて会社に行く。",ex_read:"うんどうを かねて、あるいて かいしゃに いく。",ex_cn:"也作为运动，走路去公司。"},{id:351,level:"n2",pattern:"〜を控えて",meaning:"临近〜；即将",desc:"表示时间或空间上逼近某事。",appear:5,ex_jp:"試験を控えて、学生たちは緊張している。",ex_read:"しけんを ひかえて、がくせいたちは きんちょうしている。",ex_cn:"临近考试，学生们都很紧张。"},{id:352,level:"n2",pattern:"〜を前提に",meaning:"以〜为前提",desc:"表示在某前提条件下讨论或行动。",appear:5,ex_jp:"全員参加を前提に、予定を組んだ。",ex_read:"ぜんいんさんかを ぜんていに、よていを くんだ。",ex_cn:"以全员参加为前提制定了计划。"},{id:353,level:"n2",pattern:"〜を経由して",meaning:"经由〜",desc:"表示经过某地或某途径。",appear:5,ex_jp:"香港を経由して、日本へ行く。",ex_read:"ほんこんを けいゆして、にほんへ いく。",ex_cn:"经由香港去日本。"},{id:354,level:"n2",pattern:"〜てまで",meaning:"甚至〜（不惜）",desc:"表示为了某事不惜做到这种程度。",appear:5,ex_jp:"そこまでして、彼を説得する必要があるのか。",ex_read:"そこまでして、かれを せっとくする ひつようが あるのか。",ex_cn:"有必要不惜做到那种程度去说服他吗？"},{id:355,level:"n2",pattern:"〜てしょうがない",meaning:"〜得不得了；忍不住",desc:"表示无法抑制的感情或状态。",appear:6,ex_jp:"お腹が空いてしょうがない。",ex_read:"おなかが すいてしょうがない。",ex_cn:"肚子饿得不得了。"},{id:356,level:"n2",pattern:"〜てやまない",meaning:"由衷〜；永远〜",desc:"表示内心的强烈愿望或祝福。",appear:5,ex_jp:"皆さんのご健康をお祈りしてやみません。",ex_read:"みなさんの ごけんこうを おいのりして やみません。",ex_cn:"衷心祝愿大家健康。"},{id:357,level:"n2",pattern:"〜というものだ",meaning:"这才真正是〜",desc:"表示强烈的肯定、正是如此。",appear:6,ex_jp:"これこそ本当の幸せというものだ。",ex_read:"これこそ ほんとうの しあわせという ものだ。",ex_cn:"这才真正是幸福。"},{id:358,level:"n2",pattern:"〜というものではない",meaning:"并非〜；不是〜那么回事",desc:"表示并非一概而论。",appear:5,ex_jp:"ただ働けばいいというものではない。",ex_read:"ただ はたらけば いいという ものではない。",ex_cn:"并不是说只要工作就行。"},{id:359,level:"n2",pattern:"〜とばかりに",meaning:"像要说〜似的；一副〜的样子",desc:"表示虽未明说但态度已表明一切。",appear:5,ex_jp:"彼は「知らない」とばかりに、肩をすくめた。",ex_read:"かれは「しらない」と ばかりに、かたを すくめた。",ex_cn:"他一副「不知道」的样子，耸了耸肩。"},{id:360,level:"n2",pattern:"〜とは",meaning:"竟然〜（意外/惊讶）",desc:"表示对没想到的事情感到惊讶或感叹。",appear:6,ex_jp:"彼が優勝するとは驚いた。",ex_read:"かれが ゆうしょうするとは おどろいた。",ex_cn:"他竟然夺冠了，真让人吃惊。"},{id:361,level:"n2",pattern:"〜に至って",meaning:"以至〜；到〜地步",desc:"表示事态发展到严重的地步。",appear:5,ex_jp:"事ここに至っては、どうしようもない。",ex_read:"こと ここに いたっては、どうしようもない。",ex_cn:"事已至此，无可奈何。"},{id:362,level:"n2",pattern:"〜に越したことはない",meaning:"没有比〜更好的了",desc:"表示某事物是最佳选择。",appear:5,ex_jp:"お金はあるに越したことはない。",ex_read:"おかねは あるに こしたことはない。",ex_cn:"钱当然是越多越好。"},{id:363,level:"n2",pattern:"〜にもまして",meaning:"比〜更；胜过",desc:"表示程度超过某事。",appear:5,ex_jp:"仕事にもまして、健康が大事だ。",ex_read:"しごとに もまして、けんこうが たいじだ。",ex_cn:"比工作更重要的是健康。"},{id:364,level:"n2",pattern:"〜にあって",meaning:"在〜状况下；处于〜",desc:"表示在某种处境或环境中。",appear:5,ex_jp:"困難な状況にあって、彼は諦めなかった。",ex_read:"こんなんな じょうきょうに あって、かれは あきらめなかった。",ex_cn:"在困难的情况下，他没有放弃。"},{id:365,level:"n2",pattern:"〜はともかく",meaning:"暂且不论〜",desc:"表示先把某问题放一边。",appear:5,ex_jp:"結果はともかく、よく頑張った。",ex_read:"けっかは ともかく、よく がんばった。",ex_cn:"结果暂且不论，已经很努力了。"},{id:366,level:"n2",pattern:"〜は別として",meaning:"〜另当别论",desc:"表示把某事物排除在外进行考虑。",appear:5,ex_jp:"趣味は別として、仕事には関係ない。",ex_read:"しゅみは べつとして、しごとには かんけいない。",ex_cn:"兴趣另当别论，和工作没关系。"},{id:367,level:"n2",pattern:"〜からいうと",meaning:"从〜来说",desc:"表示从某立场或观点来看。",appear:6,ex_jp:"私からいうと、それは間違いだ。",ex_read:"わたしから いうと、それは まちがいだ。",ex_cn:"从我的角度来说，那是错的。"},{id:368,level:"n2",pattern:"〜からみれば",meaning:"从〜来看",desc:"表示从某角度观察所得出的结论。",appear:6,ex_jp:"彼の立場からみれば、当然の反応だ。",ex_read:"かれの たちばから みれば、とうぜんの はんのうだ。",ex_cn:"从他的立场来看，是很自然的反应。"},{id:369,level:"n2",pattern:"〜からすれば",meaning:"从〜来看（基准）",desc:"表示以某事物为基准来看。",appear:6,ex_jp:"彼の実力からすれば、合格は間違いない。",ex_read:"かれの じつりょくから すれば、ごうかくは まちがいない。",ex_cn:"从他的实力来看，合格是毫无疑问的。"},{id:370,level:"n2",pattern:"〜としたら/〜とすれば",meaning:"如果〜的话；假设",desc:"表示假设或从某角度看。",appear:6,ex_jp:"今すぐ出発するとしたら、何時ごろ着く？",ex_read:"いますぐ しゅっぱつすると したら、なんじごろ つく？",ex_cn:"如果现在出发的话，大概几点到？"},{id:371,level:"n2",pattern:"〜はともあれ",meaning:"无论如何；且不论",desc:"表示先将某问题放一边。",appear:4,ex_jp:"理由はともあれ、結果がすべてだ。",ex_read:"りゆうは ともあれ、けっかが すべてだ。",ex_cn:"理由暂且不论，结果才是一切。"},{id:372,level:"n2",pattern:"〜でなくてなんだろう",meaning:"这不是〜又是什么呢",desc:"表示强烈的肯定反问。",appear:4,ex_jp:"これが愛でなくてなんだろう。",ex_read:"これが あいでなくてなんだろう。",ex_cn:"这不是爱又是什么呢。"},{id:373,level:"n2",pattern:"〜ではあるまいし",meaning:"又不是〜",desc:"表示否定，提醒对方注意。",appear:4,ex_jp:"子供ではあるまいし、自分で決めなさい。",ex_read:"こどもでは あるまいし、じぶんで きめなさい。",ex_cn:"又不是小孩子，自己做决定吧。"},{id:374,level:"n2",pattern:"〜にかかっている",meaning:"取决于〜",desc:"表示后项结果由前项决定。",appear:5,ex_jp:"成功するかどうかは、努力にかかっている。",ex_read:"せいこうするか どうかは、どりょくに かかっている。",ex_cn:"成功与否取决于努力。"},{id:375,level:"n2",pattern:"〜に任せて",meaning:"交给〜；任凭",desc:"表示把某事委托或交给某事或某人。",appear:5,ex_jp:"自然に任せて、見守ることにした。",ex_read:"しぜんに まかせて、みまもることにした。",ex_cn:"决定顺其自然，默默守候。"},{id:376,level:"n2",pattern:"〜に如くはない",meaning:"不如〜；没有比〜更好",desc:"表示没有比这更好的选择。",appear:4,ex_jp:"彼に如くはない。",ex_read:"かれに しくはない。",ex_cn:"没有人比他更好了。"},{id:377,level:"n2",pattern:"〜ともあろう",meaning:"堂堂〜竟然",desc:"表示对高地位者做出不相称行为的批判。",appear:4,ex_jp:"校長ともあろう方が、そんなことを言うなんて。",ex_read:"こうちょうとも あろうかたが、そんなことを いうなんて。",ex_cn:"堂堂校长竟然说那种话。"},{id:378,level:"n2",pattern:"〜と断じて",meaning:"断定〜；断言",desc:"表示断然下定结论。",appear:4,ex_jp:"これは間違いと断じていい。",ex_read:"これは まちがいと だんじて いい。",ex_cn:"可以断定这是错的。"},{id:379,level:"n2",pattern:"〜て初めて",meaning:"在〜之后才",desc:"表示经历了某事之后才首次意识到。",appear:6,ex_jp:"病気になって初めて、健康の大切さがわかった。",ex_read:"びょうきに なって はじめて、けんこうの たいせつさが わかった。",ex_cn:"生病之后才明白了健康的重要性。"},{id:380,level:"n2",pattern:"〜てはじめて",meaning:"只有〜才",desc:"表示前项是实现后项的必要条件。",appear:5,ex_jp:"努力してはじめて、成功できるのだ。",ex_read:"どりょくして はじめて、せいこうできるのだ。",ex_cn:"只有努力才能成功。"},{id:381,level:"n2",pattern:"〜かねない",meaning:"可能〜（负面）",desc:"表示有可能导致不好的结果。",appear:6,ex_jp:"そんなことをすると、彼に誤解されかねない。",ex_read:"そんなことをすると、かれに ごかいされかねない。",ex_cn:"那么做的话可能会被他误解。"},{id:382,level:"n2",pattern:"〜が最後",meaning:"一旦〜了（就完了）",desc:"表示一旦发生了前项，就会产生严重后果。",appear:5,ex_jp:"あのゲームを始めたが最後、やめられなくなる。",ex_read:"あの げーむを はじめたが さいご、やめられなくなる。",ex_cn:"一旦开始玩那个游戏，就停不下来了。"},{id:383,level:"n2",pattern:"〜と思ったら",meaning:"刚一〜就；还以为〜原来",desc:"表示动作刚刚结束就发生下一事情，或与预期不符。",appear:5,ex_jp:"桜が咲いたと思ったら、もう散ってしまった。",ex_read:"さくらが さいたと おもったら、もう ちってしまった。",ex_cn:"刚觉得樱花开了，就已经谢了。"},{id:384,level:"n2",pattern:"〜に足る",meaning:"值得～；足以～",desc:"表示有足够的价值或资格。",appear:5,ex_jp:"この本は読むに足る内容だ。",ex_read:"このほんは よむに たる ないようだ。",ex_cn:"这本书内容值得一读。"},{id:385,level:"n2",pattern:"〜を踏まえ",meaning:"基于～；根据～",desc:"表示以前项为基础来考虑。",appear:5,ex_jp:"以上の状況を踏まえ、対策を検討する。",ex_read:"いじょうの じょうきょうを ふまえ、たいさくを けんとうする。",ex_cn:"基于以上情况，探讨对策。"},{id:386,level:"n2",pattern:"〜も当然だ",meaning:"～也是理所当然",desc:"表示前项的结果是理所当然的。",appear:5,ex_jp:"彼が怒るのも当然だ。",ex_read:"かれが おこるのも とうぜんだ。",ex_cn:"他生气也是理所当然的。"}];